INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (44, 'EP206: Git Workflow: Essential Commands', 'Git has a lot of commands. Most workflows use a fraction of them.', '<h2><a href="https://go.bytebytego.com/Datadog_031426">On-call Best Practices for SREs (Sponsored)</a></h2><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://go.bytebytego.com/Datadog_031426" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="628" src="https://substackcdn.com/image/fetch/$s_!rNX-!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fb9b5395d-7f13-4ed8-9e56-0c471e99d110_1200x628.png" width="1200" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><p>On-call shouldn&#8217;t feel like constant firefighting. This guide from Datadog breaks down how high-performing SRE teams reduce alert fatigue, streamline incident response, and design rotations that don&#8217;t burn engineers out.</p><p>You&#8217;ll learn how to:</p><ul><li><p>Cut alert noise by tying signals to real user impact</p></li><li><p>Improve response with clear roles and smarter escalation paths</p></li><li><p>Turn incidents into feedback loops that improve system reliability</p></li></ul><p class="button-wrapper"><a class="button primary" href="https://go.bytebytego.com/Datadog_031426"><span>Get the guide</span></a></p><div><hr /></div><p>This week&#8217;s system design refresher:</p><ul><li><p>What&#8217;s Next in AI: 5 Trends to Watch in 2026 (Youtube video)</p></li><li><p>Git Workflow: Essential Commands</p></li><li><p>How can Cache Systems go wrong?</p></li><li><p>Top Cyber Attacks Explained</p></li><li><p>How AI Actually Generates Images</p></li></ul><div><hr /></div><h2>What&#8217;s Next in AI: 5 Trends to Watch in 2026</h2><div class="youtube-wrap" id="youtube2-cqLALf4bFPI"><div class="youtube-inner"></div></div><div><hr /></div><h2>Git Workflow: Essential Commands</h2><p>Git has a lot of commands. Most workflows use a fraction of them. The part that causes problems isn''t the commands themselves, it''s not knowing where your code sits after running one. </p><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://substackcdn.com/image/fetch/$s_!Fevp!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Feb1ae3fa-80a7-464d-97a2-869170caaa2f_2360x2960.png" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="Image" class="sizing-normal" height="1826" src="https://substackcdn.com/image/fetch/$s_!Fevp!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Feb1ae3fa-80a7-464d-97a2-869170', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/ep206-git-workflow-essential-commands', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-03-14 15:30:58.000000', '2026-03-16 06:50:54.355359', 'https://blog.bytebytego.com/p/ep206-git-workflow-essential-commands', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (45, 'Stateless Architecture: Benefits and Tradeoffs', 'In this article, we will understand the nuances of stateless architecture in more detail.', '<p style="text-align: justify;">When we hear &#8220;stateless architecture&#8221;, we often think it means building applications that have no state. That&#8217;s the wrong picture, and it can lead to confusion about everything that follows.</p><p style="text-align: justify;">Every application has a state, such as user sessions, shopping carts, authentication tokens, and preferences. All of that is state. It&#8217;s the application&#8217;s memory and the very thing that makes personalized digital experiences possible. Without it, every visit to a website would feel like the first time.</p><p style="text-align: justify;">In other words, stateless architecture doesn&#8217;t eliminate state but relocates it. Understanding where the state moves, why we move it, and what that move costs us is essential for developers.</p><p style="text-align: justify;">In this article, we will understand the nuances of stateless architecture in more detail.</p><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://substackcdn.com/image/fetch/$s_!Slmk!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F13a4978b-df30-4280-b035-299024047945_2250x2624.png" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="1698" src="https://substackcdn.com/image/fetch/$s_!Slmk!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F13a4978b-df30-4280-b035-299024047945_2250x2624.png" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><h2 style="text-align: justify;">The Problem with Keeping State on the Server</h2>
      <p>
          <a href="https://blog.bytebytego.com/p/stateless-architecture-benefits-and">
              Read more
          </a>
      </p>', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/stateless-architecture-benefits-and', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-03-12 15:31:11.000000', '2026-03-16 06:50:54.355371', 'https://blog.bytebytego.com/p/stateless-architecture-benefits-and', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (46, 'How Vimeo Implemented AI-Powered Subtitles', 'In this article, we will look at how the Vimeo engineering team overcame this problem and the decisions it made', '<h2><a href="https://go.bytebytego.com/Unleash_031126">On-Demand Webinar: Designing for Failure and Speed in Agentic Workflows with FeatureOps (Sponsored)</a></h2><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://go.bytebytego.com/Unleash_031126" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="819" src="https://substackcdn.com/image/fetch/$s_!Sm1o!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Feb1d88e9-b820-4a6f-acd9-3d510854a1cb_5120x2880.png" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><p style="text-align: justify;">Join Alex Casalboni (Developer Advocate @ Unleash) for a deep dive on how to design resilient AI workflows to make reversibility a foundational mechanism and release AI-generated code with confidence.</p><p>AI writes code in seconds, but reviews take hours. Don&#8217;t let this gap slow you down.</p><p>Watch our recent webinar to learn how FeatureOps helps you manage risk, contain blast radius, and maintain control over fast-moving agentic workflows.</p><p>In this webinar, you&#8217;ll learn how to:</p><ul><li><p>Reduce blast radius for AI-generated changes</p></li><li><p>Separate deployment from exposure at runtime</p></li><li><p>Build reversibility into agent planning and shipping</p></li></ul><p class="button-wrapper"><a class="button primary" href="https://go.bytebytego.com/Unleash_031126"><span>Watch Now</span></a></p><div><hr /></div><p style="text-align: justify;">Imagine you&#8217;re watching a video with AI-generated subtitles. The speaker is mid-sentence, clearly still talking, gesturing, making a point. But the subtitles just vanish, and there are a few seconds of blank screen. Then they reappear as if nothing happened.</p><p style="text-align: justify;">This looks like a bug. But it&#8217;s a side effect of the AI being too good at translation.</p><p style="text-align: justify;">Vimeo&#8217;s engineering team ran into this exact problem when they built LLM-powered subtitle translation for their platform. The translations themselves were excellent: fluent, natural, and often indistinguishable from human work. However, the product experience was broken because subtitles kept disappearing mid-playback, and the root cause turned out to be the AI&#8217;s own competence.</p><p style="text-align: justify;">In this article, we will look at how the Vimeo engineering team overcame this problem and the decisions it made</p><p style="text-align: justify;"><em>Disclaimer: This post is based on publicly shared details ', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/how-vimeo-implemented-ai-powered', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-03-11 15:31:15.000000', '2026-03-16 06:50:54.355380', 'https://blog.bytebytego.com/p/how-vimeo-implemented-ai-powered', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (47, 'How Airbnb Rolled Out 20+ Local Payment Methods in 360 Days', 'In this article, we will look at the technical architecture and engineering decisions that made this expansion possible.', '<h2 style="text-align: justify;"><a href="https://go.bytebytego.com/You_031026">It&#8217;s not just about getting the prompt right. (Sponsored)</a></h2><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://go.bytebytego.com/You_031026" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="819" src="https://substackcdn.com/image/fetch/$s_!-OVs!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F1136fc1a-4e7d-4dc2-9088-1affbf4a947c_1600x900.jpeg" title="" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><p>When trying to spin up AI agents, companies often get stuck in the prompting weeds and end up with agents that don&#8217;t deliver dependable results. This ebook from You.com goes beyond the prompt, revealing five stages for building a successful AI agent and why most organizations haven&#8217;t gotten there yet.</p><p>In this guide, you&#8217;ll learn:</p><ul><li><p>Why prompts alone aren&#8217;t enough and how context and metadata unlock reliable agent automation</p></li><li><p>Four essential ways to calculate ROI, plus when and how to use each metric</p></li></ul><p>If you&#8217;re ready to go beyond the prompt, this is the ebook for you.</p><p class="button-wrapper"><a class="button primary button-wrapper" href="https://go.bytebytego.com/You_031026"><span>Get the Guide</span></a></p><div><hr /></div><p style="text-align: justify;">For years, Airbnb supported credit and debit cards as the primary way guests could pay for accommodations.</p><p style="text-align: justify;">However, today Airbnb operates in over 220 countries worldwide, and while cards work well in many regions, just relying on this payment approach excludes millions of potential users. In countries where credit card penetration is low or where people strongly prefer local payment methods, Airbnb was losing bookings and limiting its growth potential.</p><p style="text-align: justify;">To solve this problem, the Airbnb Engineering Team launched the &#8220;Pay as a Local&#8221; initiative. The goal was to integrate 20+ locally preferred payment methods across multiple markets in just 14 months.</p><p style="text-align: justify;">In this article, we will look at the technical architecture and engineering decisions that made this expansion possible.</p><p style="text-align: justify;"><em>Disclaimer: This post is based on publicly shared details from the Airbnb Engineering Team. Please comment if you notice any inaccuracies.</em></p><h2 style="text-align: justify;">Understanding Local Paym', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/how-airbnb-rolled-out-20-local-payment', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-03-10 15:31:17.000000', '2026-03-16 06:50:54.355389', 'https://blog.bytebytego.com/p/how-airbnb-rolled-out-20-local-payment', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (48, 'Top AI GitHub Repositories in 2026', 'Let&#8217;s look at the most impactful AI repositories trending on GitHub right now, covering what they do, why they matter, and how they fit into the broader AI landscape.', '<h2><a href="https://go.bytebytego.com/SerpAPI_030926">Give any AI agent access to Google search with SerpApi (Sponsored)</a></h2><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://go.bytebytego.com/SerpAPI_030926" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="819" src="https://substackcdn.com/image/fetch/$s_!Ad1j!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F77387382-7887-4c80-8e36-dc42d7a173c7_3200x1800.png" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><p>Agents are smarter when they can search the web - but with SerpApi, you don&#8217;t need to reinvent the wheel. SerpApi gives your AI applications clean, structured web data from major search engines and marketplaces, so your agents can research, verify, and answer with confidence.</p><p>Access real-time data with a simple API.<strong><br /></strong></p><p class="button-wrapper"><a class="button primary" href="https://go.bytebytego.com/SerpAPI_030926"><span>Start For Free</span></a></p><div><hr /></div><p>The AI open-source ecosystem has entered an extraordinary growth phase.</p><p>GitHub&#8217;s Octoverse 2025 report revealed that over 4.3 million AI-related repositories now exist on the platform, a 178% year-over-year jump in LLM-focused projects alone. In this environment, a select group of repositories has emerged as clear frontrunners, each amassing tens or even hundreds of thousands of stars by offering developers the tools to build autonomous agents, deploy models locally, and streamline AI-powered workflows.</p><p>Let&#8217;s look at the most impactful AI repositories trending on GitHub right now, covering what they do, why they matter, and how they fit into the broader AI landscape.</p><h2>OpenClaw</h2><p>OpenClaw is the breakout star of 2026 and arguably the fastest-growing open-source project in GitHub history.</p><p>Created by PSPDFKit founder Peter Steinberger, it surged from 9,000 to over 60,000 stars in just a few days after going viral in late January 2026, and has since blown past 210,000 stars. The project was originally named Clawdbot, then Moltbot, and finally settled on OpenClaw.</p><p>At its core, OpenClaw is a personal AI assistant that runs entirely on your own devices. It operates as a local gateway connecting AI models to over 50 integrations, including WhatsApp, Telegram, Slack, Discord, Signal, and iMessage. Unlike cloud-based assistants, your data never leaves your machine. The assistant is always on, capable of browsing the web, filling out forms, ', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/top-ai-github-repositories-in-2026', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-03-09 15:31:31.000000', '2026-03-16 06:50:54.355397', 'https://blog.bytebytego.com/p/top-ai-github-repositories-in-2026', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (49, 'EP205: CPU vs GPU vs TPU', 'Why does the same code run fast on a GPU, slow on a CPU, and leave both behind on a TPU? The answer is architecture.', '<h2><strong><a href="https://go.bytebytego.com/QAWolf_030726Headline">&#9986;&#65039; Cut your QA cycles down to minutes with QA Wolf (Sponsored)</a></strong></h2><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://go.bytebytego.com/QAWolf_030726CTA" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="764" src="https://substackcdn.com/image/fetch/$s_!RVk4!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fdf71481c-87ef-4d0d-a976-b818bd864540_1600x840.png" title="" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><p>If slow QA processes bottleneck you or your software engineering team and you&#8217;re releasing slower because of it &#8212; you need to check out QA Wolf.</p><p>QA Wolf&#8217;s AI-native service <strong>supports web and mobile apps</strong>, delivering <a href="https://go.bytebytego.com/QAWolf_030726Automated">80% automated test coverage in weeks</a> and helping teams <strong>ship 5x faster</strong> by reducing QA cycles to minutes.</p><p><a href="https://go.bytebytego.com/QAWolf_030726QAWolf">QA Wolf</a> takes testing off your plate. They can get you:</p><ul><li><p>Unlimited parallel test runs for mobile and web apps</p></li><li><p>24-hour maintenance and on-demand test creation</p></li><li><p>Human-verified bug reports sent directly to your team</p></li><li><p>Zero flakes guarantee</p></li></ul><p>The benefit? No more manual E2E testing. No more slow QA cycles. No more bugs reaching production.</p><p>With QA Wolf, <a href="https://go.bytebytego.com/QAWolf_030726Drata">Drata&#8217;s team of 80+ engineers</a> achieved 4x more test cases and <strong>86% faster QA cycles</strong>.</p><p class="button-wrapper"><a class="button primary" href="https://go.bytebytego.com/QAWolf_030726CTA"><span>Schedule a demo to learn more</span></a></p><div><hr /></div><p>This week&#8217;s system design refresher:</p><ul><li><p>CPU vs GPU vs TPU</p></li><li><p>How OAuth 2 Works</p></li><li><p>How Distributed Tracing Works at the High Level?</p></li><li><p>How GPUs Work at a High Level</p></li><li><p>Top 4 API Gateway Use Cases</p></li></ul><div><hr /></div><h2>CPU vs GPU vs TPU</h2><p>Why does the same code run fast on a GPU, slow on a CPU, and leave both behind on a TPU? The answer is architecture. CPUs, GPUs, and TPUs are designed for different workloads.</p><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://substackcdn.com/image/fetch/$s_!SFnp!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2F', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/ep205-cpu-vs-gpu-vs-tpu', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-03-07 16:31:24.000000', '2026-03-16 06:50:54.355405', 'https://blog.bytebytego.com/p/ep205-cpu-vs-gpu-vs-tpu', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (50, 'How to Build High Throughput Systems', 'In this article, we will go through the fundamental concepts and practical strategies for building systems that can handle high volumes of work without breaking down under pressure.', '<p>When we build software systems, one of the most important goals is making sure they can handle large amounts of work efficiently.</p><p>High-throughput systems are capable of processing vast quantities of data or transactions in a given timeframe. Throughput refers to the amount of work a system completes in a specific time period. For example, a web server might process 10K requests per second, or a database might handle 50K transactions per minute. The higher the throughput, the more work gets done in the same amount of time.</p><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://substackcdn.com/image/fetch/$s_!AkpQ!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fbb6768d0-a8be-4773-9364-4a7400227bcf_1938x1246.png" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="936" src="https://substackcdn.com/image/fetch/$s_!AkpQ!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fbb6768d0-a8be-4773-9364-4a7400227bcf_1938x1246.png" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><p>Throughput is different from latency. Latency measures how long it takes to complete a single operation, from start to finish. While throughput measures the volume of operations the system handles over time. For example, a system can have low latency but low throughput if it processes each request quickly but can only handle a few at once. Conversely, a system might have high throughput but high latency if it processes many requests simultaneously, but each request takes longer to complete.</p><p>There is often a tradeoff between these two metrics. When we batch multiple operations together, we increase throughput because the system processes many items at once. However, this batching introduces waiting time for individual operations, which increases latency. Similarly, processing every request immediately reduces latency but may limit throughput if the system becomes overwhelmed.</p><p>In this article, we will go through the fundamental concepts and practical strategies for building systems that can handle high volumes of work without breaking down under pressure.</p><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://substackcdn.com/image/fetch/$s_!Jm65!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fcc12ef8d-a5e2-452b-806c-41a3c20d4151_2250x2624.png" target="_blank"><div class="image2-inset"><', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/how-to-build-high-throughput-systems', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-03-05 16:30:58.000000', '2026-03-16 06:50:54.355413', 'https://blog.bytebytego.com/p/how-to-build-high-throughput-systems', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (51, 'What’s Next in AI: Five Trends to Watch in 2026', 'This article covers five key trends that will likely shape how teams build with AI this year.', '<h2><a href="https://go.bytebytego.com/Orkes_030426">Technical Guide: How to Orchestrate Langchain Agents for Production (Sponsored)</a></h2><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://go.bytebytego.com/Orkes_030426" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="762" src="https://substackcdn.com/image/fetch/$s_!Uvkv!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F3de31dc1-a239-4fe9-b1fa-b840809b780d_2400x1256.png" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><p>Building with LangChain agents is easy. Running them reliably in production is not. As agent workflows grow in complexity, you need visibility, fault tolerance, retries, scalability, and human oversight. <a href="https://go.bytebytego.com/Orkes_030426">Orkes Conductor</a> provides a durable orchestration layer that manages multi agent workflows with state management, error handling, observability, and enterprise grade reliability. Instead of stitching together fragile logic, you can coordinate agents, tools, APIs, and human tasks through a resilient workflow engine built for scale. Learn how to move from experimental agents to production ready systems with structured orchestration.</p><p class="button-wrapper"><a class="button primary" href="https://go.bytebytego.com/Orkes_030426"><span>Read the Technical Guide</span></a></p><div><hr /></div><p>2026 has already started strong. In January alone, Moonshot AI open-sourced Kimi K2.5, a trillion-parameter model built for multimodal agent workflows. Alibaba shipped Qwen3-Coder-Next, an efficient coding model designed for agentic coding. OpenAI launched a macOS app for its Codex coding assistant. These are recent moves in trends that have been building for months.</p><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://substackcdn.com/image/fetch/$s_!mjnP!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F9a5749af-e11e-49b6-bebe-b764cdfbd945_1600x1538.png" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="1400" src="https://substackcdn.com/image/fetch/$s_!mjnP!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F9a5749af-e11e-49b6-bebe-b764cdfbd945_1600x1538.png" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pe', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/whats-next-in-ai-five-trends-to-watch', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-03-04 16:30:49.000000', '2026-03-16 06:50:54.355422', 'https://blog.bytebytego.com/p/whats-next-in-ai-five-trends-to-watch', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (52, 'How Agoda Built a Single Source of Truth for Financial Data', 'In this article, we will look at how the Agoda engineering team built a single source of truth for its financial data and the challenges encountered.', '<h2><a href="https://go.bytebytego.com/ScyllaDB_030326">Get first access to the Second Edition of Designing Data-Intensive Applications [O&#8217;REILLY] (Sponsored)</a></h2><p><em>Start reading the latest version of the book everyone is talking about.</em></p><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://go.bytebytego.com/ScyllaDB_030326" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="764" src="https://substackcdn.com/image/fetch/$s_!cSZH!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fd0271834-4db2-41e1-9728-8be39e2b4214_1600x840.jpeg" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><p>The second edition of Designing Data-Intensive Applications was just published &#8211; with significant revisions for AI and cloud-native!</p><p>Martin Kleppmann and Chris Riccomini help you navigate the options and tradeoffs for processing and storing data for data-intensive applications. Whether you&#8217;re exploring how to design data-intensive applications from the ground up or looking to optimize an existing real-time system, this guide will help you make the right choices for your application.</p><ul><li><p>Peer under the hood of the systems you already use, and learn how to use and operate them more effectively</p></li><li><p>Make informed decisions by identifying the strengths and weaknesses of different approaches and technologies</p></li><li><p>Understand the distributed systems research upon which modern databases are built</p></li><li><p>Go behind the scenes of major online services and learn from their architectures</p></li></ul><p>We&#8217;re offering 3 complete chapters. Start reading it today.</p><p class="button-wrapper"><a class="button primary" href="https://go.bytebytego.com/ScyllaDB_030326"><span>Download for Free</span></a></p><div><hr /></div><p>Agoda generates and processes millions of financial data points (sales, costs, revenue, and margins) every day.</p><p>These metrics are fundamental to daily operations, reconciliation, general ledger activities, financial planning, and strategic evaluation. They not only enable Agoda to predict and assess financial outcomes but also provide a comprehensive view of the company&#8217;s overall financial health.</p><p>Given the sheer volume of data and the diverse requirements of different teams, the Data Engineering, Business Intelligence, and Data Analysis teams each developed their own data pipelines to meet their specific demands. The appeal of separate data pipeline architectures li', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/how-agoda-built-a-single-source-of', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-03-03 16:30:27.000000', '2026-03-16 06:50:54.355430', 'https://blog.bytebytego.com/p/how-agoda-built-a-single-source-of', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (53, 'The Architecture Behind Open-Source LLMs', 'In this article, we will cover various open-source models and the engineering bets that define each one.', '<h2><a href="https://go.bytebytego.com/WorkOS_030226Headline">npx workos: An AI Agent That Writes Auth Directly Into Your Codebase (Sponsored)</a></h2><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://go.bytebytego.com/WorkOS_030226CTA" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="720" src="https://substackcdn.com/image/fetch/$s_!xEk7!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F4e7342e3-e6e9-4a94-9d51-e989851e2667_1280x720.png" width="1280" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><p><strong>npx workos</strong> <a href="https://go.bytebytego.com/WorkOS_020326Agent">launches an AI agent</a>, powered by Claude, that reads your project, detects your framework, and writes a complete auth integration directly into your existing codebase. It&#8217;s not a template generator. It reads your code, understands your stack, and writes an integration that fits.<br /><br />The <a href="https://go.bytebytego.com/WorkOS_030226WorkOS">WorkOS</a> agent then typechecks and builds, feeding any errors back to itself to fix.</p><p class="button-wrapper"><a class="button primary" href="https://go.bytebytego.com/WorkOS_030226CTA"><span>See how it works &#8594;</span></a></p><div><hr /></div><p>In December 2024, DeepSeek released V3 with the claim that they had trained a frontier-class model for $5.576 million. They used an attention mechanism called Multi-Head Latent Attention that slashed memory usage. An expert routing strategy avoided the usual performance penalty. Aggressive FP8 training cuts costs further.</p><p>Within months, Moonshot AI&#8217;s Kimi K2 team openly adopted DeepSeek&#8217;s architecture as their starting point, scaled it to a trillion parameters, invented a new optimizer to solve a training stability challenge that emerged at that scale, and competed with it across major benchmarks.</p><p>Then, in February 2026, Zhipu AI&#8217;s GLM-5 integrated DeepSeek&#8217;s sparse attention mechanism into their own design while contributing a novel reinforcement learning framework.</p><p>This is how the open-weight ecosystem actually works: teams build on each other&#8217;s innovations in public, and the pace of progress compounds. To understand why, you need to look at the architecture.</p><p>In this article, we will cover various open-source models and the engineering bets that define each one.</p><h2>The Common Skeleton</h2><p>Every major open-weight LLM released at the frontier in 2025 and 2026 uses a Mixture-of-Experts (MoE) transformer archite', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/the-architecture-behind-open-source', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-03-02 16:30:50.000000', '2026-03-16 06:50:54.355438', 'https://blog.bytebytego.com/p/the-architecture-behind-open-source', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (54, 'EP204: 11 Ways To Use AI To Increase Your Productivity', 'AI is changing how we work. People who use AI get more done in less time. You do not need to code. You need to know which tool to use and when.', '<h2><strong><a href="https://go.bytebytego.com/Unblocked_022826">Unblocked: Context that saves you time and tokens (Sponsored)</a></strong></h2><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://go.bytebytego.com/Unblocked_022826" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="764" src="https://substackcdn.com/image/fetch/$s_!sdgi!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F2b77faec-ea55-4b61-b56b-9ec57deeb0ad_1600x840.png" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><p>AI coding tools are fast, capable, and completely context-blind. Even with rules, skills, and MCP connections, they generate code that misses your conventions, ignores past decisions, and breaks patterns. You end up paying for that gap in rework and tokens.</p><p>Unblocked changes the economics.</p><p>It builds organizational context from your code, PR history, conversations, docs, and runtime signals. It maps relationships across systems, reconciles conflicting information, respects permissions, and surfaces what matters for the task at hand. Instead of guessing, agents operate with the same understanding as experienced engineers.</p><p>You can:</p><ul><li><p>Generate plans, code, and reviews that reflect how your system actually works</p></li><li><p>Reduce costly retrieval loops and tool calls by providing better context up front</p></li><li><p>Spend less time correcting outputs for code that should have been right in the first place</p></li></ul><p class="button-wrapper"><a class="button primary" href="https://go.bytebytego.com/Unblocked_022826"><span>See how it works</span></a></p><div><hr /></div><p>This week&#8217;s system design refresher:</p><ul><li><p>11 Ways To Use AI To Increase Your Productivity</p></li><li><p>Al Topics to Learn before Taking Al/ML Interviews</p></li><li><p>PostgreSQL versus MySQL</p></li><li><p>Why AI Needs GPUs and TPUs?</p></li><li><p>Network Protocols Explained</p></li></ul><div><hr /></div><h2>11 Ways To Use AI To Increase Your Productivity</h2><p>AI is changing how we work. People who use AI get more done in less time. You do not need to code. You need to know which tool to use and when.</p><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://substackcdn.com/image/fetch/$s_!69Ct!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fc7a9a805-e190-47e9-91ba-f28e1f5d05db_1280x1605.jpeg" target="_blank"><div class="image2-i', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/ep204-11-ways-to-use-ai-to-increase', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-02-28 16:30:26.000000', '2026-03-16 06:50:54.355446', 'https://blog.bytebytego.com/p/ep204-11-ways-to-use-ai-to-increase', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (55, 'Strong Consistency In Databases: Promises and Costs', 'In this article, we will look at what strong consistency actually means, how systems deliver it, and what it really costs.', '<p>If a database stores data on three servers in three different cities, and we write a new value, when exactly is that write &#8220;done&#8221;? Does it happen when the first server saves it? Or when all three have it? Or when two out of three confirm?</p><p>The answer to this question is quite important. Consider a simple bank transfer where we move $500 from savings to checking. We see the updated balance on our phone. But our partner, checking the same account from their laptop in another city, still sees the old balance. For a few seconds, the household has two different versions of the truth. For something similar to a like count on social media, that kind of temporary disagreement is harmless. For a bank balance, it&#8217;s a different story.</p><p>The guarantee that every reader sees the most recent write, no matter where or when they read, is what distributed systems engineers call strong consistency. It sounds straightforward. Making it work across machines, data centers, and continents is one of the hardest problems in distributed systems, because it requires those machines to coordinate, and coordination has a cost governed by physics.</p><p>In a previous article, we had looked at eventual consistency. In this article, we will look at what strong consistency actually means, how systems deliver it, and what it really costs.</p><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://substackcdn.com/image/fetch/$s_!vB9v!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fbc02c74f-e91f-438a-8ad8-d5ba6831e7f0_2250x2624.png" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="1698" src="https://substackcdn.com/image/fetch/$s_!vB9v!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fbc02c74f-e91f-438a-8ad8-d5ba6831e7f0_2250x2624.png" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><h2>What Strong Consistency Actually Promises</h2>
      <p>
          <a href="https://blog.bytebytego.com/p/strong-consistency-in-databases-promises">
              Read more
          </a>
      </p>', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/strong-consistency-in-databases-promises', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-02-26 16:30:39.000000', '2026-03-16 06:50:54.355454', 'https://blog.bytebytego.com/p/strong-consistency-in-databases-promises', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (56, 'The Algorithm That Powers Your X (Twitter) Post', 'In this article, we will look at what the algorithm does, how its components fit together, and why the xAI Engineering Team made the design choices they did.', '<h2><a href="https://go.bytebytego.com/Redis_022526">The right data. The right time.(Sponsored)</a></h2><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://go.bytebytego.com/Redis_022526" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="1852" src="https://substackcdn.com/image/fetch/$s_!qprq!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fdca6c65c-bf0a-45c5-b843-c1e86c124c84_2250x2862.png" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><p>Context engineering is the new critical layer in every production AI app, and Redis is the real-time context engine powering it. Redis gathers, syncs, and serves the right mix of memory, knowledge, tools, and state for each model call, all from one unified platform. Search across RAG, short- and long-term memory, and structured and unstructured data without stitching together a fragile multi-tool stack. With 30+ agent framework integrations across OpenAI, LangChain, Bedrock, NVIDIA NIM, and more, Redis fits the stack your teams are already building on. Accurate, reliable AI apps that scale. Built on one platform.</p><p class="button-wrapper"><a class="button primary" href="https://go.bytebytego.com/Redis_022526"><span>Explore Redis for AI</span></a></p><blockquote><div><hr /></div></blockquote><p>Every time we open X (formerly Twitter) and scroll through the &#8220;For You&#8221; tab, a recommendation system is deciding which posts to show and in what order. This recommendation system works in real-time.</p><p>In the world of social media, this is a big deal because any latency issues can cause user dissatisfaction.</p><p>Until now, the internal workings of this recommendation system were more or less a mystery. However, recently, the xAI engineering team open-sourced the algorithm that powers this feed, publishing it on GitHub under an Apache-2.0 license. It reveals a system built on a Grok-based transformer model that has replaced nearly all hand-crafted rules with machine learning.</p><p>In this article, we will look at what the algorithm does, how its components fit together, and why the xAI Engineering Team made the design choices they did.</p><p><em>Disclaimer: This post is based on publicly shared details from the xAI Engineering Team. Please comment if you notice any inaccuracies.</em></p><h2>The Big Picture</h2><p>When you request the For You feed in X, the algorithm draws from two separate sources of content:</p><ul><li><p>The first source is called in-network content. These are posts from acco', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/the-algorithm-that-powers-your-x', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-02-25 16:30:28.000000', '2026-03-16 06:50:54.355462', 'https://blog.bytebytego.com/p/the-algorithm-that-powers-your-x', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (57, 'How Uber Reinvented Access Control for Microservices', 'In this article, we will look at how the Uber engineering team built Charter and the challenges they faced.', '<h2><a href="https://go.bytebytego.com/Scylladb_022426">Don&#8217;t miss out: your free pass to Monster SCALE Summit is waiting! 50+ engineering talks on AI, databases, Rust, and more. (Sponsored)</a></h2><p><em>Monster SCALE Summit is a new virtual conference all about extreme-scale engineering and data-intensive applications.</em></p><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://go.bytebytego.com/Scylladb_022426" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="764" src="https://substackcdn.com/image/fetch/$s_!xvob!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F1342334d-35ac-4296-a74d-5374f357c318_1600x840.jpeg" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><p>Join us on March 11 and 12 to learn from engineers at Discord, Disney, LinkedIn, Uber, Pinterest, Rivian, ClickHouse, Redis, MongoDB, ScyllaDB and more. A few topics on the agenda:</p><ul><li><p>What Engineering Leaders Get Wrong About Scale</p></li><li><p>How Discord Automates Database Operations at Scale</p></li><li><p>Lessons from Redesigning Uber&#8217;s Risk-as-a-Service Architecture</p></li><li><p>Scaling Relational Databases at Nextdoor</p></li><li><p>How LinkedIn Powers Recommendations to Billions of Users</p></li><li><p>Powering Real-Time Vehicle Intelligence at Rivian with Apache Flink and Kafka</p></li><li><p>The Data Architecture behind Pinterest&#8217;s Ads Reporting Services</p></li></ul><p class="button-wrapper"><a class="button primary" href="https://go.bytebytego.com/Scylladb_022426"><span>GET YOUR FREE TICKET</span></a></p><p>Bonus: We have 500 free swag packs for attendees. And everyone gets 30-day access to the complete O&#8217;Reilly library &amp; learning platform.</p><div><hr /></div><p>Uber&#8217;s infrastructure runs on thousands of microservices, each making authorization decisions millions of times per day. This includes every API call, database query, and message published to Kafka. To make matters more interesting, Uber needs these decisions to happen in microseconds to have the best possible user experience.</p><p>Traditional access control could not handle the complexity. For instance, you might say &#8220;service A can call service B&#8221; or &#8220;employees in the admin group can access this database.&#8221; While these rules work for small systems, they fall short when you need more control. For example, what if you need to restrict access based on the user&#8217;s location, the time of day, or relationships between different pieces of d', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/how-uber-reinvented-access-control', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-02-24 16:30:15.000000', '2026-03-16 06:50:54.355470', 'https://blog.bytebytego.com/p/how-uber-reinvented-access-control', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (58, 'How Large Language Models Learn', 'In this article, we&#8217;ll explore three core concepts that have a key impact on the working of LLM', '<h2><a href="https://go.bytebytego.com/Datadog_022326">Overcome the challenges of deploying LLMs securely and at scale (Sponsored)</a></h2><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://go.bytebytego.com/Datadog_022326" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="819" src="https://substackcdn.com/image/fetch/$s_!wk2N!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fd6c9a98d-101b-4625-a59f-3802a82641b3_1920x1080.png" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><p>To scale with LLMs, you need to know how to monitor them effectively. In this eBook, get practical strategies to monitor, debug, and secure LLM-powered applications. From tracing multi-step workflows and detecting prompt injection attacks to evaluating response quality and tracking token usage, you&#8217;ll learn best practices for integrating observability into every layer of your LLM stack.</p><p class="button-wrapper"><a class="button primary" href="https://go.bytebytego.com/Datadog_022326"><span>Download the eBook</span></a></p><div><hr /></div><p>When we talk about large language models &#8220;learning,&#8221; we can end up creating a misleading impression. The word &#8220;learning&#8221; suggests something similar to human learning, complete with understanding, reasoning, and insight.</p><p>However, that&#8217;s not what happens inside these systems. LLMs don&#8217;t learn the way you learned to code or solve problems. Instead, they follow repetitive mathematical procedures billions of times, adjusting countless internal parameters until they become very good at mimicking patterns in text.</p><p>This distinction matters more than you might think because it changes the way LLMs generate their answers.</p><p>Understanding how LLMs actually work helps you know when to trust their outputs and when to be skeptical. It reveals why they can write convincing essays about topics they don&#8217;t fully understand, and why they sometimes fail in surprising ways.</p><p>In this article, we&#8217;ll explore three core concepts that have a key impact on the working of LLMs:  loss functions (how we measure failure), gradient descent (how we make improvements), and next-token prediction (what LLMs actually do).</p><h2>The Foundation: Loss Functions</h2><p>Before an LLM can learn anything, we need a way to measure how badly it&#8217;s performing. This measurement is called a loss function.</p><p>Think of it as a scoring system that provides a single number representing how wrong t', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/how-large-language-models-learn', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-02-23 16:30:39.000000', '2026-03-16 06:50:54.355478', 'https://blog.bytebytego.com/p/how-large-language-models-learn', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (59, 'EP203: RabbitMQ vs Kafka vs Pulsar', 'RabbitMQ, Kafka, and Pulsar all move messages, but they solve very different problems under the hood.', '<h2><a href="https://go.bytebytego.com/WorkOS_022126Headline">What If Adding Auth to Your App Took One Command? (Sponsored)</a></h2><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://go.bytebytego.com/WorkOS_022126CTA" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="764" src="https://substackcdn.com/image/fetch/$s_!ighn!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F217909e3-5065-4f43-8e86-740e405796bb_1600x840.png" title="" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><p><strong>npx workos</strong> <a href="https://go.bytebytego.com/WorkOS_022126Agent">launches an AI agent</a>, powered by Claude, that reads your project, detects your framework, and writes a complete auth integration directly into your existing codebase. It&#8217;s not a template generator. It reads your code, understands your stack, and writes an integration that fits.</p><p>Then it typechecks and builds, feeding any errors back to itself to fix. Just run <strong>npx workos</strong>, from <a href="https://go.bytebytego.com/WorkOS_022126WorkOS">WorkOS</a>.</p><p class="button-wrapper"><a class="button primary button-wrapper" href="https://go.bytebytego.com/WorkOS_022126CTA"><span>See how it works &#8594;</span></a></p><div><hr /></div><p>This week&#8217;s system design refresher:</p><ul><li><p>What Is Redis Really About? Why Is It So Popular? (Youtube video)</p></li><li><p>RabbitMQ vs Kafka vs Pulsar</p></li><li><p>What Are Agent Skills Really About? (Youtube video)</p></li><li><p>REST vs GraphQL</p></li><li><p>LAST CALL FOR ENROLLMENT: Become an AI Engineer - Cohort 4</p></li></ul><div><hr /></div><h2>What Is Redis Really About? Why Is It So Popular?</h2><div class="youtube-wrap" id="youtube2-z_NbVtbgBJw"><div class="youtube-inner"></div></div><div><hr /></div><h2>RabbitMQ vs Kafka vs Pulsar</h2><p>RabbitMQ, Kafka, and Pulsar all move messages, but they solve very different problems under the hood.</p><p>This diagram looks simple, but it hides three very different mental models for building distributed systems.</p><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://substackcdn.com/image/fetch/$s_!h2M_!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F1d6d88ea-4355-4f29-96fa-9770907beebb_2360x2960.png" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="Image" class="sizing-normal" height="1826" src="https://substackcdn.com/i', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/ep203-rabbitmq-vs-kafka-vs-pulsar', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-02-21 16:30:27.000000', '2026-03-16 06:50:54.355486', 'https://blog.bytebytego.com/p/ep203-rabbitmq-vs-kafka-vs-pulsar', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (60, 'LAST CALL FOR ENROLLMENT: Become an AI Engineer - Cohort 4', 'Enrollment for our upcoming Become an AI Engineer - Cohort 4 is closing soon, and classes officially begin on February 21.', '<p>Enrollment for our upcoming <strong>Become an AI Engineer - Cohort 4</strong> is closing soon, and classes officially begin on February 21. </p><p>Get 40% on your registration cost with code: <strong>BBGNL</strong></p><p class="button-wrapper"><a class="button primary" href="https://go.bytebytego.com/substack-bbai"><span>Enroll Here</span></a></p><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://go.bytebytego.com/substack-bbai" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="1456" src="https://substackcdn.com/image/fetch/$s_!byku!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Faff5628f-0867-4325-b0b9-4a5f4fd2f6ae_2360x2360.jpeg" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><p>This is not just another course about AI frameworks and tools. Our goal is to help engineers build the foundation and end to end skill set needed to thrive as AI engineers.</p><p>Here&#8217;s what makes this cohort special:</p><ul><li><p>Learn by doing: Build real world AI applications, not just by watching videos.</p></li><li><p>Structured, systematic learning path: Follow a carefully designed curriculum that takes you step by step, from fundamentals to advanced topics.</p></li><li><p>Live feedback and mentorship: Get direct feedback from instructors and peers.</p></li><li><p>Community driven: Learning alone is hard. Learning with a community is easy!</p></li></ul><p>We are focused on skill building, not just theory or passive learning. Our goal is for every participant to walk away with a strong foundation for building AI systems.</p><p>If you want to start learning AI from scratch, this is the perfect time to begin.</p><p class="button-wrapper"><a class="button primary" href="https://go.bytebytego.com/substack-bbai"><span>Enroll Here</span></a></p>', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/last-call-for-enrollment-become-an', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-02-20 16:31:57.000000', '2026-03-16 06:50:54.355494', 'https://blog.bytebytego.com/p/last-call-for-enrollment-become-an', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (61, 'Eventual Consistency: The Key Trade-Off Behind Modern Databases', 'In this article, we will look at what eventual consistency is, why it exists, how to control it, and how to handle the challenges it creates.', '<p>Eventual consistency is a key architectural choice in modern distributed systems. When we choose eventual consistency, we are making a trade-off between immediate synchronization across all database copies for better performance, scalability, and availability.</p><p>Using eventual consistency has been a key factor in our ability to build systems that serve millions of users globally. Whether we are building social media platforms, e-commerce sites, or real-time gaming applications, eventual consistency gives us the tools to handle data under load and during failures.</p><p>In this article, we will look at what eventual consistency is, why it exists, how to control it, and how to handle the challenges it creates.</p><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://substackcdn.com/image/fetch/$s_!yela!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F5ac3310f-e380-48c2-93ff-051f7606b533_2250x2624.png" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="1698" src="https://substackcdn.com/image/fetch/$s_!yela!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F5ac3310f-e380-48c2-93ff-051f7606b533_2250x2624.png" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><h2>The Problem That Eventual Consistency Solves</h2>
      <p>
          <a href="https://blog.bytebytego.com/p/eventual-consistency-the-key-trade">
              Read more
          </a>
      </p>', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/eventual-consistency-the-key-trade', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-02-19 16:30:44.000000', '2026-03-16 06:50:54.355502', 'https://blog.bytebytego.com/p/eventual-consistency-the-key-trade', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (62, 'The First 10-Year Evolution of Stripe’s Payments API', 'In this article, we look at how Stripe&#8217;s payment APIs evolved over the years, the technical challenges they faced, and the engineering decisions that shaped modern payment processing.', '<h2><strong><a href="https://go.bytebytego.com/QAWolf_021826Headline">&#9986;&#65039; Cut your QA cycles down to minutes with QA Wolf (Sponsored)</a></strong></h2><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://go.bytebytego.com/QAWolf_021826CTA" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="764" src="https://substackcdn.com/image/fetch/$s_!RVk4!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fdf71481c-87ef-4d0d-a976-b818bd864540_1600x840.png" title="" width="1456" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><p>If slow QA processes bottleneck you or your software engineering team and you&#8217;re releasing slower because of it &#8212; you need to check out QA Wolf.</p><p>QA Wolf&#8217;s AI-native service <strong>supports web and mobile apps</strong>, delivering <a href="https://go.bytebytego.com/QAWolf_021826Automated">80% automated test coverage in weeks</a> and helping teams <strong>ship 5x faster</strong> by reducing QA cycles to minutes.</p><p><a href="https://go.bytebytego.com/QAWolf_021826QAWolf">QA Wolf</a> takes testing off your plate. They can get you:</p><ul><li><p>Unlimited parallel test runs for mobile and web apps</p></li><li><p>24-hour maintenance and on-demand test creation</p></li><li><p>Human-verified bug reports sent directly to your team</p></li><li><p>Zero flakes guarantee</p></li></ul><p>The benefit? No more manual E2E testing. No more slow QA cycles. No more bugs reaching production.</p><p>With QA Wolf, <a href="https://go.bytebytego.com/QAWolf_021826Drata">Drata&#8217;s team of 80+ engineers</a> achieved 4x more test cases and <strong>86% faster QA cycles</strong>.</p><p class="button-wrapper"><a class="button primary" href="https://go.bytebytego.com/QAWolf_021826CTA"><span>Schedule a demo to learn more</span></a></p><div><hr /></div><p>When Stripe first launched, they became known for integrating payment processing into any business with just seven lines of code.</p><p>This was a really big achievement. Taking something as complex as credit card processing and reducing it to a simple code snippet felt revolutionary. In essence, a developer could open a terminal, run a basic curl command, and immediately see a successful credit card payment.</p><p>However, building and maintaining a payment API that works across dozens of countries, each with different payment methods, banking systems, and regulatory requirements, is one of the most difficult problems. Most of the time, companies either lock themselves into supporting j', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/the-first-10-year-evolution-of-stripes', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-02-18 16:31:13.000000', '2026-03-16 06:50:54.355511', 'https://blog.bytebytego.com/p/the-first-10-year-evolution-of-stripes', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (63, 'How Cloudflare Eliminates Cold Starts for Serverless Workers', 'Cut Code Review Time & Bugs in Half (Sponsored)', '<h2><a href="https://go.bytebytego.com/Coderabbit_021726">Cut Code Review Time &amp; Bugs in Half (Sponsored)</a></h2><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://go.bytebytego.com/Coderabbit_021726" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="362" src="https://substackcdn.com/image/fetch/$s_!Fkc-!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F7591b803-4cc8-4604-9ce8-7d87828ed1ac_1600x800.png" width="724" /><div class="image-link-expand"><div class="pencraft pc-display-flex pc-gap-8 pc-reset"><button class="pencraft pc-reset pencraft icon-container restack-image" tabindex="0" type="button"><svg fill="none" height="20" stroke="var(--color-fg-primary)" stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg"><g><title></title><path d="M2.53001 7.81595C3.49179 4.73911 6.43281 2.5 9.91173 2.5C13.1684 2.5 15.9537 4.46214 17.0852 7.23684L17.6179 8.67647M17.6179 8.67647L18.5002 4.26471M17.6179 8.67647L13.6473 6.91176M17.4995 12.1841C16.5378 15.2609 13.5967 17.5 10.1178 17.5C6.86118 17.5 4.07589 15.5379 2.94432 12.7632L2.41165 11.3235M2.41165 11.3235L1.5293 15.7353M2.41165 11.3235L6.38224 13.0882"></path></g></svg></button><button class="pencraft pc-reset pencraft icon-container view-image" tabindex="0" type="button"><svg class="lucide lucide-maximize2 lucide-maximize-2" fill="none" height="20" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2" viewBox="0 0 24 24" width="20" xmlns="http://www.w3.org/2000/svg"><polyline points="15 3 21 3 21 9"></polyline><polyline points="9 21 3 21 3 15"></polyline><line x1="21" x2="14" y1="3" y2="10"></line><line x1="3" x2="10" y1="21" y2="14"></line></svg></button></div></div></div></a></figure></div><p>Code reviews are critical but time-consuming. CodeRabbit acts as your AI co-pilot, providing instant Code review comments and potential impacts of every pull request.</p><p>Beyond just flagging issues, CodeRabbit provides one-click fix suggestions and lets you define custom code quality rules using AST Grep patterns, catching subtle issues that traditional static analysis tools might miss.</p><p>CodeRabbit reviews 1 million PRs every week across 3 million repositories and is used by 100 thousand Open-source projects.</p><p>CodeRabbit is free for all open-source repo&#8217;s.</p><p class="button-wrapper"><a class="button primary" href="https://go.bytebytego.com/Coderabbit_021726"><span>Get Started Today</span></a></p><div><hr /></div><p>Cloudflare has reduced cold start delays in its Workers platform by 10 times through a technique called worker sharding.</p><p>A cold start occurs when serverless code must initialize completely before handling a request. For Cloudflare Workers, this initialization involves four distinct phases:</p><ul><li><p>Fetching the JavaScript source code from storage</p></li><li><p>Compiling that code into executable machine instructions</p></li><li><p>Executing any top-level initialization code</p></li><li><p>Finally, invoking the code to handle the incoming request</p></li></ul><p>See the diagram below:</p><div class="captioned-image-container"><figure><a class="image-link image2 is-viewable-img" href="https://substackcdn.com/image/fetch/$s_!WE0h!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fe55034fd-5e86-475d-9283-3dd26abc2070_2880x2448.png" target="_blank"><div class="image2-inset"><source type="image/webp" /><img alt="" class="sizing-normal" height="1238" src="https://substackcdn.com/image/fetch/$s_!WE0h!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fe55034fd-5e86-475d-9283-3dd26abc2070_2880x2448.png" width="1456" /><d', 7, '字节跳动技术团队', 'https://blog.bytebytego.com/p/how-cloudflare-eliminates-cold-starts', 'ByteByteGo', 'blog', '["\u6280\u672f", "\u67b6\u6784"]', '2026-02-17 16:31:17.000000', '2026-03-16 06:50:54.355519', 'https://blog.bytebytego.com/p/how-cloudflare-eliminates-cold-starts', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (64, '工业级AI视频厂商再融资，掌握120TB独家数据，营收破亿 | 硬氪首发', '作者&nbsp;|&nbsp;乔钰杰
  编辑&nbsp;|&nbsp;袁斯来
  硬氪获悉，重庆达瓦合志影像科技有限公司（下称“达瓦科技”）宣布完成近亿元的新一轮融资。本轮融资由一村资本、宝捷会创新基金领投，老股东启赋资本、重庆永川国资平台持续跟投。
  达瓦科技成立于2023年，总部位于重庆，是国内首个实现商业化闭环的专业级AI内容创作平台，并打通“生产+交易+履约”全链条的视频AI生态。2025年，达瓦科技营收突破亿元，三年复合增长率近300%，AI平台实现规模化收入。
  达瓦科技的核心壁垒，建立在极其稀缺的120TB独家影视级结构化数据集之上。这套数据集包含镜头级、光学级、表演级等300多种标注要素，颗粒度精确到场景级。与依赖公开成片结果的通用模型不同，达瓦科技的数据源自200多个头部商业项目的真实拍摄过程。
  创始人卢琪向硬氪介绍，传统数据集往往只有“输入文本-输出视频”的简单映射，而达瓦科技的数据包含了能教会AI“如何做出好内容”的深度决策信息。
  “创作结果只能教会AI模仿，创作过程才能教会AI思考和判断。公开数据只包含‘好结果’，而达瓦科技的数据包含废案、妥协方案', '<p>作者&nbsp;|&nbsp;乔钰杰</p>
  <p>编辑&nbsp;|&nbsp;袁斯来</p>
  <p>硬氪获悉，重庆达瓦合志影像科技有限公司（下称“达瓦科技”）宣布完成近亿元的新一轮融资。本轮融资由一村资本、宝捷会创新基金领投，老股东启赋资本、重庆永川国资平台持续跟投。</p>
  <p>达瓦科技成立于2023年，总部位于重庆，是国内首个实现商业化闭环的专业级AI内容创作平台，并打通“生产+交易+履约”全链条的视频AI生态。2025年，达瓦科技营收突破亿元，三年复合增长率近300%，AI平台实现规模化收入。</p>
  <p>达瓦科技的核心壁垒，建立在极其稀缺的120TB独家影视级结构化数据集之上。这套数据集包含镜头级、光学级、表演级等300多种标注要素，颗粒度精确到场景级。与依赖公开成片结果的通用模型不同，达瓦科技的数据源自200多个头部商业项目的真实拍摄过程。</p>
  <p>创始人卢琪向硬氪介绍，传统数据集往往只有“输入文本-输出视频”的简单映射，而达瓦科技的数据包含了能教会AI“如何做出好内容”的深度决策信息。</p>
  <p>“创作结果只能教会AI模仿，创作过程才能教会AI思考和判断。公开数据只包含‘好结果’，而达瓦科技的数据包含废案、妥协方案和导演批注。这些‘负样本’对AI理解商业取舍逻辑以及角色也是核心要素。”卢琪介绍称。</p>
  <p>在专业视频领域，封装能力的重要性已超越模型能力本身。针对通用模型指令模糊、结果不稳定以及不理解专业黑话等痛点，达瓦科技构建了中间层的专业化封装能力，包含七维质量评估体系、影视行业知识图谱和经典分镜逻辑等，通过将行业know-how注入模型，让AI能够理解“好视频”的标准，确保输出内容符合商业需求。</p>
  <p>公司旗下的FilmOS内容工业AI平台，能把一个创意需求，直接转化成包含分镜、AI素材、预算和拍摄计划的完整执行方案。同时，团队可以在共享空间里和多个AI助手协同工作，让AI参与全流程创意决策。此外，每一次协作的过程都会被记录下来，逐渐沉淀成团队自己的创作风格和方法。</p>
  <p>市场方面，目前在大预算影视工业市场，FilmOS能将项目前期筹备周期从4-6周缩短至3-5天，预算精确度提升60%，显著降低超支风险，并利用AI提高推荐供应商的匹配度。而在中规模内容生产市场，达瓦科技的AI自动化生产流程能够将短剧的单部制作成本降低40%，在保证稳定内容产出的基础上显著缩短制作周期。</p>
  <p>达瓦科技运营的永川科技片场，是国内使用率超过90%的高质量虚拟拍摄影棚。它不仅是影视制作的生产设施，也是达瓦科技持续吸引客户、积累数据的“数据工厂”。片场产生的包括导演决策逻辑、摄影师运镜技巧、制片人管控经验等“黄金数据”会再次进入FilmOS平台，经过清洗标注后成为训练模型的新燃料，形成自我强化的“数据飞轮”。</p>
  <p>值得注意的是，达瓦科技自定位于“产业路由器”而非单纯的SaaS工具，这一定位源于其深度连接了产业链上的关键节点。作为国家级数字资产基础设施运营方，公司参与了4项国家标准的制定，深度绑定160多家生态企业、数千家注册导演和演员以及三万多家制作供应商，构筑了较强的生态壁垒。</p>
  <p>本轮融资后，达瓦科技将继续迭代300亿参数的专业视频垂直AI模型，并加速FilmOS在专业内容创作领域的商业化应用。</p>', 8, '36氪', 'https://36kr.com/p/3723669408987782?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 03:53:57.000000', '2026-03-16 06:50:55.159873', 'https://36kr.com/p/3723669408987782?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (65, 'AWE首秀亮王牌：慕思，凭什么让一众科技大佬集体“躺平”？', '智能家居发展十余年，各类智能单品早已走进千家万户，但一个困局却始终未能突破：单品“智能化”多流于表面，且彼此孤立，难以串联成一个真正懂生活、主动服务人真实需求的“智能之家”。
  比如用于交流的语音助手，虽能随叫随应，但也会成为某一刻的噪音；又如守护安全的摄像头，并不能感知被褥之下人体的真实状态；即便是可掌控全屋智能的手机，却也不是24小时被人贴身操控。
  “全域协同”、“主动服务”、“无感存在”至今仍是智能家居难以破解的重要问题。
  而今，作为硬件智能家居的年度风向标，AWE2026将AI融合下的科技，投向硬件智能与家居场景的深度适配，破解“智能不智”的痛点。
  所以可以看到，在这个新科技元素全覆盖的展会上，一幅想象中的未来家居生态图景正在徐徐展开：可整理散落杂物的管家机器人、懂情绪的智能玩偶、能主动管理健康的智能床……
  这其中，睡眠赛道无疑是这场未来智能家居生态展览上的焦点，赛道引领者思最具看点。它不仅是家居行业唯一以“双展位”形式登陆AWE2026的企业，更携手华为鸿蒙，以“鸿蒙智选 慕思智能床Pro H-DESIGN”新品，将智能睡眠体验拉到科技界聚光灯的中心。余承东', '<p>智能家居发展十余年，各类智能单品早已走进千家万户，但一个困局却始终未能突破：单品“智能化”多流于表面，且彼此孤立，难以串联成一个真正懂生活、主动服务人真实需求的“智能之家”。</p>
  <p>比如用于交流的语音助手，虽能随叫随应，但也会成为某一刻的噪音；又如守护安全的摄像头，并不能感知被褥之下人体的真实状态；即便是可掌控全屋智能的手机，却也不是24小时被人贴身操控。</p>
  <p>“全域协同”、“主动服务”、“无感存在”至今仍是智能家居难以破解的重要问题。</p>
  <p>而今，作为硬件智能家居的年度风向标，AWE2026将AI融合下的科技，投向硬件智能与家居场景的深度适配，破解“智能不智”的痛点。</p>
  <p>所以可以看到，在这个新科技元素全覆盖的展会上，一幅想象中的未来家居生态图景正在徐徐展开：可整理散落杂物的管家机器人、懂情绪的智能玩偶、能主动管理健康的智能床……</p>
  <p>这其中，睡眠赛道无疑是这场未来智能家居生态展览上的焦点，赛道引领者思最具看点。它不仅是家居行业唯一以“双展位”形式登陆AWE2026的企业，更携手华为鸿蒙，以“鸿蒙智选 慕思智能床Pro H-DESIGN”新品，将智能睡眠体验拉到科技界聚光灯的中心。余承东、尼格买提等各界名人纷纷来此打卡，沉浸式体验智能睡眠的全新可能。</p>
  <p>而慕思，也完成从传统家居制造商到全场景睡眠健康科技企业的范式跃迁。</p>
  <p class="image-wrapper"><img src="https://img.36krcdn.com/hsossms/20260314/v2_7ea69929f49e47e7aa9ff0ab3606168a@6208419_oswg1830662oswg3200oswg2133_img_jpg?x-oss-process=image/quality,q_90/format,jpg/interlace,1" /></p>
  <p class="img-desc">AWE2026展会-慕思展台</p>
  <h2><strong>唯一双展位登陆AWE，家居领域慕思独占鳌头</strong></h2>
  <p>3月12日，2026年中国家电及消费电子博览会（AWE2026）在上海盛大开幕。作为中国规格最高的家电及消费电子展览会，今年AWE展会吸引了全球1200家企业参展，既有海尔、华为等传统领军企业，也有追觅、宇树科技、影石Insta360等众多科技圈新贵。</p>
  <p>本届AWE展会上，睡眠大健康领域让人耳目一新。代表国内健康睡眠标杆的慕思，登陆AWE完成首秀，并以双展位形式重磅参展，成为家居行业的独一份。</p>
  <p>虽是双展位，但慕思在场景打造上各有侧重。据慕思CTO陈文泽介绍，品牌自有展区围绕慕思自有产品展开，主要聚焦旗下睡眠核心产品，涵盖鸿蒙系列、T系列旗舰机型等产品；而华为鸿蒙展区，慕思则以睡眠新品为切入点，与华为鸿蒙生态下的照明、卫浴等智能产品联动，呈现一个智慧家庭生活全场景。</p>
  <p>慕思两大展区的最大亮点，无疑是其全新力作——鸿蒙智选 慕思智能床Pro H-DESIGN，这也是该产品在全球的正式展现。作为鸿蒙智选慕思智能床Pro的迭代之作，该产品在智能化体验、材质等方面实现了质的飞跃。正因为它的魅力加持，慕思展区瞬间成为AWE2026火爆的“网红打卡点”。</p>
  <p>在人头攒动的慕思展区，众多观众争相“躺床”打卡。更有华为高管余承东、杨海松，央视主持人尼格买提等科技、传媒界名人亲临现场，感受科技睡眠带来的全新“躺平式”体验。</p>
  <p class="image-wrapper"><img src="https://img.36krcdn.com/hsossms/20260314/v2_bf7a579f45fe4ff1ac32c247c2784f24@6208419_oswg133014oswg1024oswg580_img_jpg?x-oss-process=image/quality,q_100/format,jpg/interlace,1" /></p>
  <p class="img-desc">央视主持人尼格买提现场体验慕思智能床</p>
  <p>一方是智能睡眠领域的领跑者，一方是科技界的大佬，看似不相干的慕思与华为鸿蒙，却成功“牵手”，这段跨界“姻缘”的背后，藏着二者对“科技赋能睡眠”的共同追求。去年6月，慕思成为华为鸿蒙在智能睡眠领域的唯一深度合作伙伴，从此开启全场景智能睡眠生态的新篇章。</p>
  <p>成果随之落地。同年9月，双方携手推出首款力作——鸿蒙智选 慕思智能床Pro，它不仅搭载了行业领先的“左右六区独立智控”技术，更成为首个接入“星闪互联”技术的智能床产品，慕思在技术层面实现了与华为生态的深度互通。</p>
  <p>产品之外，渠道也成为二者互通的着力点。从华为的线上商城到线下智慧生活馆，慕思均以智能床稳居睡眠空间c位，且打通了从“拓客引流”到“场景体验”的完整链路。</p>
  <p class="image-wrapper"><img src="https://img.36krcdn.com/hsossms/20260314/v2_3281a49f0ed24789babc2e1eca514f48@6208419_oswg2159246oswg4674oswg3117_img_jpg?x-oss-process=image/quality,q_80/format,jpg/interlace,1" /></p>
  <p class="img-desc">华为鸿蒙展区慕思智能床产品</p>
  <p>而本届AWE展现的新品“鸿蒙智选 慕思智能床Pro H-DESIGN”，正是慕思与华为鸿蒙生态深度合作的又一里程碑。慕思CTO陈文泽透露，“华为鸿蒙是我们的优质合作伙伴，在合作过程中，我们相互赋能和帮助。在此基础上，我们进一步优化原有产品，提升用户体验，从而为消费者提供更好的选择。”</p>
  <p>可以预见，慕思与华为鸿蒙联合打造的智能床，或将从单一的寝具，变成卧室乃至全屋的智慧终端。在智慧卧室场景中，它可串联起灯光、空调、窗帘等智能化设备，且任意切换模式。甚至还能化身全屋智能一切的“开始键”，与温湿度、新风乃至影音系统实现无缝协同。</p>
  <p>这既让困扰国人多年的睡眠问题有了科技化的解决方案，也为智能家居生活打开了未来新生态的场景之门：一张聪明的床，可链接全屋智能的万千可能。</p>
  <p>慕思，由此蜕变成全场景智能睡眠健康平台。AWE的舞台，正是慕思对世界的宣告。“慕思近年在智能化睡眠体验方面有了大幅度进步，借助AWE这个大型科技类展会，我们既想向全国乃至全球公众展示慕思睡眠产品的最新成果，同时也希冀向行业传递慕思正在向科技化、智能化转型的决心。”慕思CTO陈文泽如是说。</p>
  <h2><strong>一张智能床，何以成为人类健康的“智慧中枢”？</strong></h2>
  <p>探索智能睡眠多年的慕思，正如本届AWE展会所呈现的，以持续迭代的产品，早已收获广大用户的满满赞誉。而在专业领域，这份探索同样赢得了权威认可。</p>
  <p>就在AWE启幕当天，AWE2026艾普兰奖重磅揭晓，鸿蒙智选 慕思智能床Pro H-DESIGN一举摘得AWE艾普兰创新奖，收获这个有着“全球智慧生活领域奥斯卡”奖项的肯定，于慕思而言，更是动力。</p>
  <p class="image-wrapper"><img src="https://img.36krcdn.com/hsossms/20260314/v2_672edd0a572e4b6a895980c3ab4aff61@6208419_oswg1712914oswg3183oswg2122_img_jpg?x-oss-process=image/quality,q_90/format,jpg/interlace,1" /></p>
  <p class="img-desc">鸿蒙智选 慕思智能床Pro H-DESIGN获得AWE艾普兰创新奖</p>
  <p>而这份荣誉的背后，是慕思顶尖技术与极致体验的双重支撑。</p>
  <p>以鸿蒙智选 慕思智能床Pro H-DESIGN为例，它深度回应了国人个性化的睡眠需求。基于慕思20余年私人定制经验，床体采用左右分区设计，用户可根据喜好，在5-7.5级间自由调节软硬度。同时，它还能智能识别姿势变化，主动调节肩、腰、腿三大分区软硬度，实现智能跟随的舒适体验。再有新创的“柔性唤醒”功能，通过渐进式律动，让用户从深睡自然过渡到清醒，告别闹钟惊扰，更有利于精神健康。</p>
  <p>而这些“善解人意”，主要源自慕思的硬核科技：自研的国家二类医疗器械认证的核心传感器、数百个“柔性调节柱”等技术，才得以成就一张懂睡眠、更懂健康的床。</p>
  <p>值得一提的是，慕思新品接入华为鸿蒙独有的星闪技术，实现超高速配网、超强抗干扰力，加之超低时延、易操控等优势，让智能床使用更简单快捷。</p>
  <p>真正彰显其实力的，远不止于此。这一次，慕思在材质工艺与智能化体验等方面实现全面进阶。比如三排十字拉点工艺、超高吸湿率纤维、针织拟梭织高端工艺的运用，让床垫拥有顶奢质感和舒适度外，还自带呼吸感；翻身随调功能、智能微撑腰功能的呈现，让睡眠更体贴。</p>
  <p>慕思在智能睡眠领域越走越深的底气，来自其对技术创新的坚持。据统计，2025', 8, '36氪', 'https://36kr.com/p/3722669939931524?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 02:00:50.000000', '2026-03-16 06:50:55.159921', 'https://36kr.com/p/3722669939931524?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (66, '中国最大家电展上，一批想帮你做家务的机器人来了！', '文｜邱晓芬
  编辑｜苏建勋
  2026年，挤进具身智能机器人赛道的主力军，是一众家电企业。
  3月12日-15日，中国最大的家电及消费电子博览会（AWE 2026）在上海举办。和往年不同的是，此次展会的亮点已经从过去的家电，变成了具身智能机器人。
  有终端、有数据的大小家电企业，自然而然把家庭服务当做机器人的核心目标，展示了一系列功能——家庭巡逻、老人防护、简单家务、甚至是下厨房等等。
  不过，经过《智能涌现》体验，这些功能设计还比较早期，运行的速度也比较慢，稳定性不太够，但也呈现了一幅机器人在家庭生活中的图景。
  在不远的未来，不想做家务的人有救了。
  追觅：能干活的“轮椅机器人”
  今年AWE上，追觅大手笔包下了七千平方米的E7馆，展示了追觅的所有新品类，除了洗地机、扫地机、小家电，还有飞行器、机器人、汽车、眼镜等等，整个展馆被观众挤得水泄不通。
  追觅还展出了一台“轮椅机器人”。现场工作人员对我们说，依靠四个轮，这台机器人可以从卧室开到阳台，稳定又快捷，家里的老人还可以把它当做轮椅。
  在这台轮椅机器人上，还有一双多功能仿生机械手。在未来，它还可以操控洗地机、', '<p><strong>文｜邱晓芬</strong></p>
  <p><strong>编辑｜苏建勋</strong></p>
  <p>2026年，挤进具身智能机器人赛道的主力军，是一众家电企业。</p>
  <p>3月12日-15日，中国最大的家电及消费电子博览会（AWE 2026）在上海举办。和往年不同的是，此次展会的亮点已经从过去的家电，变成了具身智能机器人。</p>
  <p>有终端、有数据的大小家电企业，自然而然把家庭服务当做机器人的核心目标，展示了一系列功能——家庭巡逻、老人防护、简单家务、甚至是下厨房等等。</p>
  <p>不过，经过《智能涌现》体验，这些功能设计还比较早期，运行的速度也比较慢，稳定性不太够，但也呈现了一幅机器人在家庭生活中的图景。</p>
  <p>在不远的未来，不想做家务的人有救了。</p>
  <h3><strong>追觅：能干活的“轮椅机器人”</strong></h3>
  <p>今年AWE上，追觅大手笔包下了七千平方米的E7馆，展示了追觅的所有新品类，除了洗地机、扫地机、小家电，还有飞行器、机器人、汽车、眼镜等等，整个展馆被观众挤得水泄不通。</p>
  <p>追觅还展出了一台“轮椅机器人”。现场工作人员对我们说，依靠四个轮，这台机器人可以从卧室开到阳台，稳定又快捷，家里的老人还可以把它当做轮椅。</p>
  <p>在这台轮椅机器人上，还有一双多功能仿生机械手。在未来，它还可以操控洗地机、吸尘器、洗衣机、烘干机。现场工作人员称，追觅的具身智能大模型已积累了路径规划、环境感知等能力，能支持语音指令理解、视觉导航、避障。</p>
  <p class="image-wrapper"><img src="https://img.36krcdn.com/hsossms/20260314/v2_87917742031745368d8388f4a46448ad@1199336245_oswg238921oswg1080oswg1441_img_000?x-oss-process=image/format,jpg/interlace,1" /></p>
  <p class="img-desc">△追觅“轮椅机器人”，图源：《智能涌现》拍摄</p>
  <p>针对扫地机无法清洁角落的痛点，追觅还在扫地机上装上了机械臂和清洁圆盘。</p>
  <p>在现场，追觅X60 Pro 圆盘版移动到椅子边，伸出了带拖布圆盘的机械臂，清洁椅子底下的污渍。</p>
  <p class="image-wrapper"><img src="https://img.36krcdn.com/hsossms/20260314/v2_eb8de62358fd416bbcb42cf43b7423bd@1199336245_oswg505912oswg1080oswg721_img_000?x-oss-process=image/format,jpg/interlace,1" /></p>
  <p class="img-desc">△追觅X60 Pro 圆盘版</p>
  <h3><strong>科沃斯：机器人装小龙虾，数字分身来了</strong></h3>
  <p>科沃斯给全新的家庭服务管家机器人起名为「八界」，这也是AWE上唯一接入OpenClaw的机器人。</p>
  <p>现场工作人员称，「八界」的设计理念是，让机器人从“家里的设备”升级为“人在外时的用户分身”。</p>
  <p class="image-wrapper"><img src="https://img.36krcdn.com/hsossms/20260314/v2_71fbccb8be1c493e991047a4fbbd6910@1199336245_oswg51673oswg1080oswg810_img_000?x-oss-process=image/format,jpg/interlace,1" /></p>
  <p class="img-desc">△八界机器人接入小龙虾，图源：智能涌现拍摄</p>
  <p>想象一下，当你在办公室工作时，可以在飞书上给机器人发消息，让「八界」帮你整理家里的桌面、收纳玩具、取东西、整理凌乱的鞋子、或是把衣服放进洗衣机等等。</p>
  <p class="image-wrapper"><img src="https://img.36krcdn.com/hsossms/20260314/v2_e4dca3f884944b8ba87ee208aeacb941@1199336245_img_000?x-oss-process=image/format,jpg/interlace,1" /></p>
  <p class="img-desc">△八界帮忙收纳鞋子，图源：《智能涌现》拍摄</p>
  <p>在现场，「八界」展示了鞋子收纳的场景。只是，它收纳的速度比较慢，不如自己亲自上手，在连接OpenClaw之后，也出现了不稳定的情况，需要多次下指令提示。</p>
  <p>不过，科沃斯讲解人员称，「八界」机器人具备了长期记忆的学习能力，在未来，不需要每次干活都要重复教学，会越用越聪明。</p>
  <h3><strong>海尔：机器人通知你，该吃药了</strong></h3>
  <p>海尔此次展出了一台企鹅形状的家庭陪伴机器人。</p>
  <p>这款机器人可以精准识别家里的老人是否跌倒，并且远程通知子女。另外，它还可以定时提醒老人吃药、陪老人聊天、帮他们规划日程等等。</p>
  <p class="image-wrapper"><img src="https://img.36krcdn.com/hsossms/20260314/v2_ae4cab8d11354fbb9f1909fa57747bb4@1199336245_img_000?x-oss-process=image/format,jpg/interlace,1" /></p>
  <p class="img-desc">△海尔的陪伴机器人，图源：《智能涌现》拍摄</p>
  <p>海尔也展出了清洁机器人的另外一个形态。</p>
  <p>基于脏污感知、三维语义感知，机器人能借助上面的吸尘器帮忙清理，解决传统清洁机器人二次污染、需要人工清理等痛点。此外，机器人上面还安了夹爪，可以帮忙捡垃圾等等。</p>
  <p class="image-wrapper"><img src="https://img.36krcdn.com/hsossms/20260314/v2_b4dfa52bf87c4a9a98a7e0ab9b3e283e@1199336245_oswg45857oswg1080oswg608_img_000?x-oss-process=image/format,jpg/interlace,1" /></p>
  <p class="img-desc">△海尔的清洁机器人，图源：《智能涌现》拍摄</p>
  <h3><strong>TCL：当陪伴机器人可分体、可换装</strong></h3>
  <p>TCL此次展出了分体式AI机器人AiMe，萌萌的外表吸引了很多女性观众在现场合照打卡。</p>
  <p>AiMe和其他陪伴机器人最大的区别是分体式设计，由三个部分组成：一个可以随身佩戴的交互设备（Mini Core随行伴侣）、机器人上半身、充电仓。</p>
  <p>当你在其他房间时，可以在Mini Core上，用语音呼叫AiMe，它就会根据信号定位自动回到你身边。通过这个交互设备，你还可以随时查看机器人视角里家庭的情况。</p>
  <p class="image-wrapper"><img src="https://img.36krcdn.com/hsossms/20260314/v2_292eba4753f948739ad39e1bd2841f8c@1199336245_img_000?x-oss-process=image/format,jpg/interlace,1" /></p>
  <p class="img-desc">△AiMe机器人，图源：《智能涌现》拍摄</p>
  <p>当然，AiMe还有最基本的情绪价值作用，比如在家里陪孩子讲故事、唠嗑解闷。此外，它还可以根据你的喜好，更换外装。</p>
  <p class="image-wrapper"><img src="https://img.36krcdn.com/hsossms/20260314/v2_2e11771725674b1fa87d8f40e05af873@1199336245_oswg388955oswg1080oswg818_img_000?x-oss-process=image/format,jpg/interlace,1" /></p>
  <p class="img-desc">Aime</p>
  <h3><strong>海信：给看球的你拿瓶冰可乐</strong></h3>
  <p>海信一次性推出了三款机器人，其中最有意思的是他们的管家机器人Savvy。</p>
  <p>轮式底盘的设计，让机器人可以灵活穿梭在家里。据海信的工作人员介绍，机器人的底层系统已经与家电打通，Savvy可以实现对海信冰箱、空调、洗衣机、电视等家电的智能联动控制。</p>
  <p>在未来，Savvy可以帮忙把脏衣服扔进洗衣机里，控制洗衣机开始洗衣服。</p>
  <p>或者是，当识别到你在', 8, '36氪', 'https://36kr.com/p/3722882943334789?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-14 14:37:39.000000', '2026-03-16 06:50:55.159975', 'https://36kr.com/p/3722882943334789?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (67, '腾讯龙虾团队答疑：龙虾的热度确实高过能力，但它是普通人拥抱 AI 浪潮的第一步', '文｜王毓婵
  编辑｜苏建勋
  最近一周，一向以风格稳重著称的腾讯一反常态，不仅借着一场“免费帮装虾”的线下活动迅速推高了大众对“龙虾”的热情，而且在短期内推出了大量“龙虾”产品。
  目前已经上线的，有被称为腾讯版“免部署小龙虾”的办公工具WorkBuddy；支持一键启动，并将AI代理能力接入微信和QQ双端的QClaw；面向开发者的腾讯云轻量应用服务器Lighthouse，以及配套生态与安全工具Skillhub等等。CEO马化腾在朋友圈披露，接下来，腾讯还会推出自研龙虾、本地虾、云端虾、企业虾、云桌面虾，安全隔离虾房、云保安、知识库等等一系列产品。
  OpenClaw，别称“龙虾”，是当下最火的Agent开源框架。这款可以被直接部署在电脑本地的Agent，能像人类一样操作系统、访问文件、回复消息，同时突破生理极限，7*24小时不间断干活。
  春节后，龙虾成为了“大厂必争之地”。字节跳动旗下火山引擎上线了 ArkClaw，阿里云通义实验室则推出了 CoPaw，普通人装龙虾的门槛被迅速抹平。但关于龙虾到底能做什么，以及如何规避信息泄露、误删文件等风险，大众仍然有诸多疑问。
  3月', '<p><strong>文｜王毓婵</strong></p>
  <p><strong>编辑｜苏建勋</strong></p>
  <p>最近一周，一向以风格稳重著称的腾讯一反常态，不仅借着一场“免费帮装虾”的线下活动迅速推高了大众对“龙虾”的热情，而且在短期内推出了大量“龙虾”产品。</p>
  <p>目前已经上线的，有被称为腾讯版“免部署小龙虾”的办公工具WorkBuddy；支持一键启动，并将AI代理能力接入微信和QQ双端的QClaw；面向开发者的腾讯云轻量应用服务器Lighthouse，以及配套生态与安全工具Skillhub等等。CEO马化腾在朋友圈披露，接下来，腾讯还会推出自研龙虾、本地虾、云端虾、企业虾、云桌面虾，安全隔离虾房、云保安、知识库等等一系列产品。</p>
  <p>OpenClaw，别称“龙虾”，是当下最火的Agent开源框架。这款可以被直接部署在电脑本地的Agent，能像人类一样操作系统、访问文件、回复消息，同时突破生理极限，7*24小时不间断干活。</p>
  <p>春节后，龙虾成为了“大厂必争之地”。字节跳动旗下火山引擎上线了 ArkClaw，阿里云通义实验室则推出了 CoPaw，普通人装龙虾的门槛被迅速抹平。但关于龙虾到底能做什么，以及如何规避信息泄露、误删文件等风险，大众仍然有诸多疑问。</p>
  <p>3月12日晚，腾讯“龙虾特攻队”接受了包括36氪在内的多家媒体的采访。腾讯云开发者AI产品负责人丁宁、腾讯轻量云总监钟宇澄、腾讯云安全总经理苏建东、AI Agent 安全中心负责人谢奕智透露了“摆摊帮装虾”这场活动的前因后果，并回答了关于安全、商业化和产品矩阵的诸多问题。</p>
  <p><strong>以下是对话实录，36氪对内容进行了不影响原意的删减：</strong></p>
  <h3><strong>关于“摆摊帮装虾”：一次无心插柳的全民 AI 实验</strong></h3>
  <p><strong>Q：3月6日腾讯总部大楼下的“摆摊帮装虾”活动是怎么实现的？当初是如何筹备的？</strong></p>
  <p>钟宇澄：整个过程其实非常迅速。3月1日，我们在公司内部发放了几百张免费的轻量云 OpenClaw 体验券，原本预估应该够用，没想到不到20秒就被抢购一空。之后许多同事咨询如何安装和运行，我们就想干脆在腾讯滨海大厦北广场做一次线下的装机活动。</p>
  <p>最初的想法比较简单，仅面向内部同事，所以定在3月6日周五举办。但后来和同事们聊起这个想法，大家觉得可以扩大范围，让司外有兴趣的用户也参与进来。于是我们在活动前两天通过视频号发了预告，没想到视频直接火了，超出了我们的预期。</p>
  <p>在人员安排上，我们最初只招募了10名志愿者，由团队的核心产品和研发同事对他们进行了一两个小时的快速培训，教他们如何帮用户部署及演示基础场景。看到视频号的热度后，我们将志愿者扩充到了20人。</p>
  <p>活动当天，由于早上九点就有用户开始排队，我们又临时从云服务器计算团队增援了近10名志愿者。</p>
  <p>现场的情况非常令人感慨，来的用户各行各业都有：60多岁的退休工程师、推着婴儿车的妈妈、小学生等等。其中约80%的人是非技术背景，纯粹是对 AI 感兴趣 。我们原计划每人五分钟装完，但实际上一对一介绍和调试平均要花二三十分钟，甚至有人在现场待了一整天。当天我们在线下帮500多人完成了装机，整个事件的发酵完全超出了我们的预料。</p>
  <p><strong>Q：所以这只是一个“无心插柳”的活动吗？在开始前，是否有想过通过这次活动为腾讯其他“龙虾”产品宣传造势的营销动机？活动结束后，内部是如何评价的？</strong></p>
  <p>钟宇澄：实话实说，开始时真的没想那么多。当时 WorkBuddy 和 QClaw 更多还在内部阶段，没有正式对外推。我们的初衷只是因为云端部署 OpenClaw 比本地部署更复杂，需要跟用户解释清楚 。事件影响力扩大后，各产品开始快速协同，共同组成了现在的“腾讯龙虾”产品矩阵。</p>
  <p><strong>Q：很��开发者反馈“养虾”非常消耗算力和内存。最近一个月，腾讯云后台是否看到了明显的 Token 消耗上涨？如果热度持续，是否会带来算力压力？</strong></p>
  <p>钟宇澄：具体的 Token 统计由于涉及用户隐私和权限，我们并没有去做精确的统计。但可以预见的是，整个模型算力的消耗量确实比之前增加了不少，只不过目前还没有具体的量化数据。</p>
  <h3><strong>关于安全与架构：闭源产品的“护城河”</strong></h3>
  <p><strong>Q：X 上曾有人通过指令诱导 OpenClaw交出了 API Key。如果我使用WorkBuddy，当它扫到类似指令时，会不会也执行命令把我的私密 API Key 发到评论区？</strong></p>
  <p>丁宁：这里需要明确一下，OpenClaw 是开源方案，而 WorkBuddy 是闭源产品。从架构上看，WorkBuddy 集成了我们自研且投产很长时间的能力，比如 CodeBuddy、Cloud Studio 里的 Gateway Server 和 Agent OS。我们在几年前就有比较成熟的针对开发者的 Sandbox（沙箱）机制，改一改就能变成 Agent OS。</p>
  <p>再加上腾讯安全实验室提供的方案，对软件供应链投毒等行为都有很好的防范。最关键的是，WorkBuddy 只对用户个人指定的工作文件夹内容生效。比如你做本地文件整理或格式转换，它就在你指定的范围内工作，权限没有那么大，所以不会出现你担心的那种越权行为。</p>
  <p><strong>Q：那如果有人从 GitHub 上拉取代码，或者利用 WorkBuddy 往 Skill Hub 投毒，你们能检测出来吗？</strong></p>
  <p>谢奕智：我们会检测出来。腾讯内部有多个实验室，创新性地提出了用“Agent 对抗 Agent”的自动化审核机制。我们内部有多道防线，从传统的基于规则、特征，到用AI针对恶意代码进行检测机制，从源头杜绝恶意插件的流入。在创建和上传环节都会集成这个能力，一旦识别到风险就会主动拦截。</p>
  <p><strong>Q：广大网友有个担忧，会不会在WorkBuddy里捆绑安装弹窗广告等功能？</strong></p>
  <p>丁宁：WorkBuddy团队是做AI Coding的CodeBuddy团队。我们是从做DevOps、代码仓库、制品库起家的，所以我们没有您刚才说的这种广告基因。WorkBuddy内置的Skills都是我们自己审核过的，没有问题。但如果用户自己从第三方找的插件，这就跟用户在手机上非要装未经审核的应用一样。</p>
  <h3><strong>范式革命：为什么是“龙虾”火了？</strong></h3>
  <p><strong>Q：OpenClaw 的火爆让人联想到 ChatGPT 时刻，这两轮浪潮有什么不同？有人说大模型只代表龙虾的智商，你们怎么看大模型和龙虾的关系？</strong></p>
  <p>丁宁：这是一个从“对话”到“执行”的范式变化。大模型最早只是一个对话框，而现在的 OpenClaw 加速了这种模式的推广。当 AI Coding 发展到 Autonomous Development 阶段时，Backend Agent 和 Skills 已经能支持更多的泛生产力场景。即使你不懂代码，也可以享受到这种“言出法随”的红利。OpenClaw 给了大家一种希望，虽然产品形态早已有之，但它的火爆确实让这种模式更精确地为人所知。</p>
  <p>钟宇澄：我觉得龙虾不像 ChatGPT 那样属于革命性的技术突破，它更多是让普通大众能近距离感受到 AI Agent。龙虾能做的事情，在 2025 年的一些工具里其实也能做到，但对大众来说门槛太高。虽然它现在配置起来依然相对复杂，但它仍然是当前市面上能让大部分人快速感受到 AI 给生活带来变化的最好选择。</p>
  <p><strong>Q：有人质疑龙虾的热度超过了能力，调侃它是“头顶铝锅”时代的产物，甚至说是为了解决 Token 消耗过慢的焦虑。你们怎么看这些声音？</strong></p>
  <p>钟宇澄：焦虑因素或多或少会有，目前它确实也还做不到“一人公司”那种程度。但从我们上周五在腾讯大厦做的线下装机活动来看，情况很不一样。现场有 60 多岁的退休工程师，也有推着婴儿车的妈妈。虽然有人嘲讽他们不懂龙虾是在浪费时间，但我觉得他们能走出这一步去真正上手接触 AI，就已经比大部分人进步了。对于这些人群来说，龙虾是他们拥抱 AI 浪潮的一个具体抓手。</p>
  <h3><strong>商业化与未来：从“单兵”到“团队”</strong></h3>
  <p><strong>Q：WorkBuddy 1 月份就在内部用了，为什么选在这周正式上线？是为了赶这波热度吗？</strong></p>
  <p>丁宁：确实有关系，热度加快了我们的节奏。我们原本准备在3月中旬发布。去年 DeepSeek火的时候大家都在休假办公，今年为了防止这种情况，我们年初就做好了提前发布的准备。既然年后这个 timing 到了，我们就直接发了。</p>
  <p>现在的版本相比 1 月份最大的迭代是连通了 IM 工具的长链接，可以通过手机 QQ、飞书、微信进行远端操作。既然要做 AI Teams，这些场景我', 8, '36氪', 'https://36kr.com/p/3721355722684804?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-14 11:19:44.000000', '2026-03-16 06:50:55.160004', 'https://36kr.com/p/3721355722684804?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (68, '前华为北美高管团队创业AIDC算力电源赛道，正推进与国际大厂合作 | 硬氪首发', '作者&nbsp;|&nbsp;林晴晴
  编辑&nbsp;|&nbsp;袁斯来
  硬氪获悉，AIDC全栈算力电源解决方案提供商「梅威斯Matrix Power」已于近日完成A轮融资，由星星充电独家投资，金额为数千万元，治臻咨询担任其长期独家财务顾问。此前公司曾获某上市公司天使轮、宇杉资本Pre-A轮投资。本轮资金将主要用于AI数据中心电源的持续研发、海外市场拓展及流动资金补充。
  梅威斯电气技术（上海）有限公司成立于2020年，是一家专注于AI数据中心（AIDC）算力电源的解决方案商。公司专注于高效、高密度电源产品的研发，产品线覆盖从传统54VDC机柜内供电到下一代±400V/800V HVDC柜外架构，再到固态变压器等前沿技术。
  随着AI算力需求的爆发式增长，单机柜功率正从数十千瓦跃升至兆瓦级，传统UPS加铅酸电池的供电架构在空间、能效和动态响应上已难以支撑高密度GPU集群的运转。全球数据中心电力设备市场预计到2028年将接近7000亿人民币。然而，国内外市场呈现出截然不同的节奏。美国市场在技术应用和投资力度上遥遥领先，预计到2030年市场规模将达400亿美金；而中国市场尽管', '<p>作者&nbsp;|&nbsp;林晴晴</p>
  <p>编辑&nbsp;|&nbsp;袁斯来</p>
  <p>硬氪获悉，AIDC全栈算力电源解决方案提供商「梅威斯Matrix Power」已于近日完成A轮融资，由星星充电独家投资，金额为数千万元，治臻咨询担任其长期独家财务顾问。此前公司曾获某上市公司天使轮、宇杉资本Pre-A轮投资。本轮资金将主要用于AI数据中心电源的持续研发、海外市场拓展及流动资金补充。</p>
  <p>梅威斯电气技术（上海）有限公司成立于2020年，是一家专注于AI数据中心（AIDC）算力电源的解决方案商。公司专注于高效、高密度电源产品的研发，产品线覆盖从传统54VDC机柜内供电到下一代±400V/800V HVDC柜外架构，再到固态变压器等前沿技术。</p>
  <p>随着AI算力需求的爆发式增长，单机柜功率正从数十千瓦跃升至兆瓦级，传统UPS加铅酸电池的供电架构在空间、能效和动态响应上已难以支撑高密度GPU集群的运转。全球数据中心电力设备市场预计到2028年将接近7000亿人民币。然而，国内外市场呈现出截然不同的节奏。美国市场在技术应用和投资力度上遥遥领先，预计到2030年市场规模将达400亿美金；而中国市场尽管增速迅猛，但由于高端GPU获取受限，市场规模约为美国的四分之一。当前，台达凭借收购的通信电源技术占据全球约80%的份额，光宝紧随其后，但多数厂商或局限于传统UPS领域，或由工业电源匆忙转型，缺乏真正理解AI数据中心高压直流架构的基因。</p>
  <p class="image-wrapper"><img src="https://img.36krcdn.com/hsossms/20260314/v2_2439991045654efeb217e5d8318700c3@15419058_oswg143510oswg1080oswg573_img_000?x-oss-process=image/format,jpg/interlace,1" /></p>
  <p class="img-desc">梅威斯| AIDC算力电源拼图（图源/企业）</p>
  <p>针对这一市场空白，硬氪了解到，「梅威斯」构建了从当前到未来的完整AIDC全栈电源解决方案。其现有及在研产品线全面覆盖54VDC机柜内电源，包括支持5.5kW和12kW的PSU（电源供应单元）、集成锂电池管理的BBU（电池备份单元）、结合超级电容实现500微秒级超快响应的CBU（电容备份单元）以及240V DC的BBS（电池备份系统）。面向下一代数据中心，公司计划推出±400V/800V HVDC柜外电源，其HVDC Sidecar模块单柜最大功率可达1.2MW，系统效率在97.3%至97.7%之间，负载动态响应时间为500微秒。更进一步，公司已开始布局固态变压器（SST）技术，旨在未来直接从10kV中压电网转换为800V直流，消除多级转换损耗，为GW级AI工厂提供终极供电方案。</p>
  <p class="image-wrapper"><img src="https://img.36krcdn.com/hsossms/20260314/v2_bbfa582bed784ac9bd8c854e6e77d261@15419058_oswg149514oswg1080oswg452_img_000?x-oss-process=image/format,jpg/interlace,1" /></p>
  <p class="img-desc">英伟达从415伏交流（上）到800伏直流（下）的配电架构演进（图源/企业）</p>
  <p>市场验证方面，「梅威斯」前期通过通信电源业务验证了自身的技术与交付能力，在东南亚市场积累了良好的客户基础。截至目前，公司在手订单近亿元，本轮融资后，将加速推进北美市场的布局。技术迭代与市场速度仍是行业核心挑战，公司将加快AI电源的研发进度，同时推进800V HVDC及固态变压器等前沿技术的产品化，以应对NVIDIA等巨头推动的2027年起800V DC原生服务器大规模商用趋势。</p>
  <p>据「梅威斯」战略发展及融资负责人Jackie介绍，公司目前正在积极推进与Google、Meta等北美互联网巨头就算力电源业务的合作；同时，团队也与国内头部算力服务器厂家，就860KW级别的超高算力AIDC服务器的电源设计开展研发合作。</p>
  <p>硬氪了解到，「梅威斯」团队为市场少见的华为系电源班底。创始人李小华曾任华为网络能源部北美区副总裁，曾带领华为团队作为OCP组织电源架构的主导方，基于20多年的通信电源经验，为谷歌、Meta设计全球首个基于54V直流和锂电池架构的分布式OCP数据中心电源；CTO为前华为数字能源模块电源子业务、前华为数字能源综合智慧能源子业务高管；技术总监为前台达技术主管，专注电源行业22年。公司核心技术团队成员在华为、台达、艾默生、Eltek、Tyco等企业拥有超过20年的技术积累，是国内少数深度参与OCP电源架构设计的团队之一。</p>
  <p><strong>投资方观点</strong></p>
  <p>星星充电：作为本轮独家投资方，星星充电对梅威斯在&nbsp;AIDC 算力电源领域的技术实力和市场前瞻性表示高度认可。我们看到，随着AI算力需求的爆发，传统供电架构已难以满足行业发展，而梅威斯凭借其华为系核心团队的深厚积累，构建了覆盖当前与未来的全栈电源解决方案，尤其在高压直流领域展现出领先优势。此次投资不仅是对梅威斯电源技术路线的肯定，更是星星充电布局未来能源基础设施的重要落子。我们相信，梅威斯将在AIDC数据中心电源市场占据重要地位，并为全球绿色高效算力基础设施建设贡献关键力量。</p>', 8, '36氪', 'https://36kr.com/p/3722683801909641?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-14 11:10:52.000000', '2026-03-16 06:50:55.160024', 'https://36kr.com/p/3722683801909641?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (69, '9点1氪丨济州航空空难一年后再现遇难者遗骸；中国区“苹果税”下调；市监局出手整治“误导性大小字”广告', '今日热点导览
  美团王兴：“减少登味”，内部不要再叫我“兴哥”
  斯泰兰蒂斯回应“玛莎拉蒂品牌要被出售”
  8年超龄车延期3年营运？滴滴辟谣
  微软市值5个月内蒸发1万亿美元
  金融监管总局约谈5家平台运营机构
  TOP3大新闻
  韩媒：济州航空空难一年后再现遇难者遗骸
  据韩联社、《韩民族日报》等韩媒报道，对于2024年12月致179人遇难的韩国济州航空空难案，韩国近期重启对失事客机残骸的调查并再次发现遇难者遗骸。截至3月12日，现场累计已发现33块遗骨，其中9块经DNA比对确认属于7名遇难者。
  报道称，针对此事，韩国总统李在明12日下令，要求彻底调查事故初期遗骸未被收殓的原委，以及遗骸被搁置一年多的经过。
  当地时间2024年12月29日，由泰国曼谷起飞的韩国济州航空7C2216号航班在位于全罗南道的务安机场降落时坠毁。机上175名乘客和6名机组人员，除2名乘务员获救，其余179人全部遇难。这是在韩国国内发生的伤亡最严重的空难事故。（财联社）
  中国区“苹果税”下调
  苹果发布通知：自2026年3月15日起，适用于中国内地（大陆）App Store的iOS', '<h2><strong>今日热点导览</strong></h2>
  <p>美团王兴：“减少登味”，内部不要再叫我“兴哥”</p>
  <p>斯泰兰蒂斯回应“玛莎拉蒂品牌要被出售”</p>
  <p>8年超龄车延期3年营运？滴滴辟谣</p>
  <p>微软市值5个月内蒸发1万亿美元</p>
  <p>金融监管总局约谈5家平台运营机构</p>
  <h2><strong>TOP3大新闻</strong></h2>
  <p><strong>韩媒：济州航空空难一年后再现遇难者遗骸</strong></p>
  <p>据韩联社、《韩民族日报》等韩媒报道，对于2024年12月致179人遇难的韩国济州航空空难案，韩国近期重启对失事客机残骸的调查并再次发现遇难者遗骸。截至3月12日，现场累计已发现33块遗骨，其中9块经DNA比对确认属于7名遇难者。</p>
  <p>报道称，针对此事，韩国总统李在明12日下令，要求彻底调查事故初期遗骸未被收殓的原委，以及遗骸被搁置一年多的经过。</p>
  <p>当地时间2024年12月29日，由泰国曼谷起飞的韩国济州航空7C2216号航班在位于全罗南道的务安机场降落时坠毁。机上175名乘客和6名机组人员，除2名乘务员获救，其余179人全部遇难。这是在韩国国内发生的伤亡最严重的空难事故。（财联社）</p>
  <p><strong>中国区“苹果税”下调</strong></p>
  <p>苹果发布通知：自2026年3月15日起，适用于中国内地（大陆）App Store的iOS及iPadOS佣金率将进行调整。Apple App内购买及付费App的标准佣金率将由目前的30%改为25%。App Store Small Business Program以及Mini Apps Partner Program项下符合条件的Apple App内购买佣金率以及第一年后的自动续费订阅佣金率将由目前的15%改为12%。（央视新闻）</p>
  <p><strong>市监局出手整治“误导性大小字”广告</strong></p>
  <p>市场监管总局印发《关于强化广告中提示性用语监管工作的通知》（以下简称《通知》），部署对相关广告乱象开展为期半年的清理整治工作。</p>
  <p>《通知》确定了整治“误导性大小字”广告、依法查处未显著标明提示性用语的广告、依法查处违法使用绝对化用语的广告、加强引证广告监管、强化广告主自证广告内容监管、强化对主要广告发布媒介监管等六方面重点任务，要求各级市场监管部门切实加大对“大字吸睛、小字免责”“随意宣称第一、首创、最佳”“萝卜坑式引证”以及弱化标示对消费者不利信息等营销乱象的清理整治力度，坚决依法查处严重欺骗误导消费者、扰乱市场竞争秩序的广告违法行为，积极推动优质广告资源与高品质产品对接，缓解广告主“营销焦虑”，引导广告活动各方经营者主动摈弃“文字游戏”式广告。（界面新闻）</p>
  <h2><strong>大公司/大事件</strong></h2>
  <p><strong>美团王兴：“减少登味”，内部不要再叫我“兴哥”&nbsp;</strong></p>
  <p>3月13日上午美团召开2026年管理层沟通会。美团CEO王兴表示，“Agent对我的冲击比ChatGPT冲击更大。”对于美团来说，物理世界的数字化将是AI非常重要的底座。他还表示将坚定国际化，但不会盲目扩张。</p>
  <p>在提及对公司管理者的期待时，王兴表示应该努力减少登味，“比如大家习惯叫我‘兴哥’，我觉得这是‘登味’明显的叫法。从我开始，大家从这一刻开始不要再叫我兴哥了，叫我王兴就好。我们从自身做起，去拥抱新事物、新潮流。”（第一财经）</p>
  <p><strong>斯泰兰蒂斯回应“玛莎拉蒂品牌要被出售”&nbsp;</strong></p>
  <p>就“Stellantis（斯泰兰蒂斯）集团可能会解体、玛莎拉蒂品牌可能会出售”等传闻，3月13日，Stellantis集团亚太区执委会成员、传播副总裁王超向新京报贝壳财经记者回应表示，玛莎拉蒂品牌不对外出售。有关“Stellantis集团正考虑一项计划，拟对集团进行拆分”的说法毫无任何事实依据，此类相关断言纯属臆测和捏造。</p>
  <p>针对“Stellantis集团正在与中国车企探讨合作方案，希望通过引入中国资本为欧洲业务注入资金，并已与小米集团和小鹏汽车进行接触，讨论Stellantis集团欧洲业务的重组方案”这一传闻，王超表示，“我们对猜测性报道不予置评。”（新京报）</p>
  <p><strong>去哪儿被指擅改航班，消费者要求退还原票款并按其原本的购票金额进行三倍赔偿</strong></p>
  <p>近日，有消费者反映在“去哪儿旅行”APP购票后遭遇航班被擅自更改。重庆蹇女士称，她于2月1日花费6234元购买三张三亚至重庆机票，2月24日临行前发现航班被从17：05篡改为23：25的“红眼航班”，且未收到通知。</p>
  <p>蹇女士表示，因随行有儿童不便深夜乘机，与平台沟通无果后，她被迫花费23000元另购返程公务舱机票。她认为平台操作失误造成其额外损失，要求退还原票款并按三倍赔偿。去哪儿网回应称，系代理商预订错误，已处罚涉事代理，并赔付蹇女士二次购票的实际损失23000元。但对于其提出的原订单票款三倍赔偿诉求，平台表示无法满足。（澎湃新闻）</p>
  <p><strong>8年超龄车延期3年营运？滴滴辟谣</strong></p>
  <p>3月13日，滴滴出行发布辟谣声明称，近日部分社交平台流传多则不实信息，称“滴滴推出新政策，8年超龄车可以延期三年继续营运，符合条件就能线上办理”。滴滴严格按照国家和地方相关法律法规及平台规定执行准入和清退标准，从未推出所谓“8年超龄车延期3年营运”的政策，任何声称可以在滴滴办理满8年后延期的，均为谣言。</p>
  <p>《滴滴平台用户规则》和车主端《加入滴滴的条件说明和承诺》均明确说明，车主注册车辆的车龄已超过8年或行驶里程已超60万公里，不符合车辆准入标准，不予准入。滴滴严格遵循国家法规和各地监管要求，司机端系统自动识别车龄，超8年的车辆无法正常注册绑定出车，无任何“超龄车违规延期”“内部特殊通道”等政策，所谓“放宽条件”均为虚假信息。滴滴方面表示，目前网络上标注“延期超龄车”“超龄车跑滴滴教程”的视频，多借助AI批量出现，信息纯属捏造，疑似黑灰产引流内容。滴滴称，对于上述传播不实信息，严重误导司机的行为，滴滴将保留追究其法律责任的权利。（界面新闻）</p>
  <p><strong>LABUBU联名三丽鸥盲盒上新秒售罄，隐藏款被炒至近千元溢价超5倍</strong></p>
  <p>3月12日晚10点，泡泡玛特旗下新款LABUBU盲盒“美梦奇遇记”上线，该系列是泡泡玛特与三丽鸥合作推出的全新搪胶公仔盲盒系列。蓝鲸记者在开售当晚实测抢购，进入购买页面后随即显示“排队人数过多”，短短数秒内，该系列盲盒便已售罄。随后记者查询发现，不仅官方小程序，淘宝、抖音、得物等全平台均显示无货。</p>
  <p>记者观察发现，该系列盲盒一经发售便在转售市场出现溢价，得物APP显示，当前该系列多个款式中，普通款如凯蒂猫、库洛米已分别涨至239元和200元；而隐藏款“经典凯蒂猫”更是溢价至919元，较159元的发售价已上涨超过5倍，并且价格仍在持续走高。（蓝鲸新闻）</p>
  <p><strong>茅台渠道新政落地：非标产品全面代销，渠道提取5%销售佣金</strong></p>
  <p>从渠道人士处获悉，近日，茅台各省区经销商联谊会召开会议，明确陈年茅台15年、精品茅台、生肖茅台及公斤茅台等非标茅台全面实行代销制。根据安排，上述产品须通过i茅台按官方统一价格对外销售，渠道可提取5%销售佣金（月结）。此外，茅台还设定了相关考核要求。茅台代销制是指货权仍归属厂家，经销商无需预付全额货款，仅需缴纳保证金即可开展销售。（财联社）</p>
  <p><strong>曝��星拿下2000万块iPhone Fold屏幕订单，5月开始量产</strong></p>
  <p>韩媒ajunews3月12日发布博文，报道称在苹果供应链中，三星的统治力正空前强化，已拿下苹果首款折叠手机iPhone Fold高达2000万块的面板订单，并预估于2026年5月开始量产。</p>
  <p>供应链消息称苹果iPhone Fold的初期订单量为1300万块，随后增加到1500万块，最新数据显示已追加到2000万块，增幅约20%。为消化庞大的苹果订单，三星显示正在紧急重组生产线。公司目前正将忠清南道牙山工厂的核心产线改造为iPhone与折叠屏专属生产线，全力备战下半年的量产高峰。（IT之家）</p>
  <p><strong>贵州茅台财务总监、董秘蒋焰被查</strong></p>
  <p>据贵州省纪委监委派驻贵州茅台酒厂（集团）有限责任公司纪检监察组、遵义市纪委监委消息：贵州茅台酒股份有限公司党委委员、副总经理、财务总监、董事会秘书蒋焰涉嫌严重违纪违法，目前正接受贵州省纪委监委派驻贵州茅台酒厂（集团）有限责任公司纪检监察组纪律审查和遵义市监委监察调查。（中新经纬）</p>
  <p><strong>微软市值5个月内蒸发1万亿美元</strong></p>
  <p>微软股价过去几个月来持续下滑。3月12日美股收盘，微软股价下滑0.75%至401.86美元，市值为2.98万亿美元。而在去年10月底，微软股价峰值约为540美元，市值超过4万亿美元。不到5个', 8, '36氪', 'https://36kr.com/p/3722103811226244?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-14 01:23:11.000000', '2026-03-16 06:50:55.160066', 'https://36kr.com/p/3722103811226244?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (70, '国泰航空2025年净利润达108亿港元，载客量增长近三成｜最前线', '作者｜黄楠
  编辑｜袁斯来
  国泰航空（00293.HK）近日公布2025年全年业绩。财报数据显示，国泰集团2025年实现收益1167.66亿港元，同比增长11.9%；集团应占溢利108亿港元，同比增长9.1%。这是国泰连续第三年录得盈利，三年累计盈利超过300亿港元，已覆盖疫情期间的累计亏损。
  业绩主要受客运运力持续恢复和载客率维持高位驱动。官方数据显示，2025年国泰航空及香港快运合计载客达3600万人次，同比增长27%。但客运收益率随市场供应增加而正常化，部分抵销了收入增幅。
  运力扩张仍在继续。2025年国泰集团新增20个航点，其中国泰航空新增长沙、乌鲁木齐等5个内地航点，
  当前国泰占香港机场超过50%的份额，国泰集团行政总裁林绍波表示，国泰将继续平衡发展国际网络与内地连接，目前集团国际航点超过80个，内地航点24个、是往来香港与内地航线最多的非内地航司。这一结构将保持动态优化。
  2026年国泰集团计划再增约10%的客运运力，主要通过加密现有航线实现。
  国泰航空（图源/企业）
  货运业务方面，载货吨数录得增长，同时贸易环境不确定性对运价形成压力。
', '<p>作者｜黄楠</p>
  <p>编辑｜袁斯来</p>
  <p>国泰航空（00293.HK）近日公布2025年全年业绩。财报数据显示，国泰集团2025年实现收益1167.66亿港元，同比增长11.9%；集团应占溢利108亿港元，同比增长9.1%。这是国泰连续第三年录得盈利，三年累计盈利超过300亿港元，已覆盖疫情期间的累计亏损。</p>
  <p>业绩主要受客运运力持续恢复和载客率维持高位驱动。官方数据显示，2025年国泰航空及香港快运合计载客达3600万人次，同比增长27%。但客运收益率随市场供应增加而正常化，部分抵销了收入增幅。</p>
  <p>运力扩张仍在继续。2025年国泰集团新增20个航点，其中国泰航空新增长沙、乌鲁木齐等5个内地航点，</p>
  <p>当前国泰占香港机场超过50%的份额，国泰集团行政总裁林绍波表示，国泰将继续平衡发展国际网络与内地连接，目前集团国际航点超过80个，内地航点24个、是往来香港与内地航线最多的非内地航司。这一结构将保持动态优化。</p>
  <p>2026年国泰集团计划再增约10%的客运运力，主要通过加密现有航线实现。</p>
  <p class="image-wrapper"><img src="https://img.36krcdn.com/hsossms/20260313/v2_39ddbd6033b148db8b58edfb7e38e4de@6022551_oswg1183493oswg1928oswg978_img_png?x-oss-process=image/quality,q_90/format,jpg/interlace,1" /></p>
  <p class="img-desc">国泰航空（图源/企业）</p>
  <p>货运业务方面，载货吨数录得增长，同时贸易环境不确定性对运价形成压力。</p>
  <p>受贸易摩擦影响，2025年，内地至美国航线需求有所下滑。国泰货运通过调整航线网络，将运力转向东南亚和印度市场，同时拓展高价值货物类型，全年载货吨数增长达11.4%。</p>
  <p>国泰顾客及商务总裁刘凯诗表示，鲜活农产品、药品和高科技元件成为新的增长点。针对大湾区出口需求，国泰货运已开通鲜活产品专属快线，缩短岭南荔枝、海鲜等产品的运输时效。</p>
  <p>作为国泰集团双品牌战略的一部分，香港快运2025年运载旅客近800万人次，运力增长超过三成。但受日本地震传言影响，暑期旺季需求受到冲击，财务表现承压。</p>
  <p>2026年香港快运将聚焦三个方向：加速东南亚和中国内地网络布局、提升大湾区市场渗透率、丰富增值服务产品。目前，香港快运已有三分之一收入来自大湾区。</p>
  <p>据林绍波透露，2023年至2025年是国泰历史上财务表现最佳的三年，但2026年行业将逐步回归正常化，外部挑战正在增多——燃油价格因中东局势近期近乎翻倍，贸易摩擦带来的不确定性仍在。</p>
  <p>针对近期燃油价格飙升，国泰已采取燃油套保（覆盖30%用量）和调整燃油附加费两项应对措施，目标是保持现有运力不缩减。</p>
  <p>业绩发布同日，国泰航空宣布增购14架波音777-9飞机，对该机型的总订购数量增至35架。</p>
  <p>国泰集团主席贺以礼表示，过去数年集团已订购逾100架新飞机，涵盖窄体机、区域宽体机、长途宽体机及大型货机，包括波音777-9、空客A330-900及A350F货机。新飞机订单连同新客舱产品、机场贵宾室及数字化创新的投资，集团总投资额远超1000亿港元。2026年将先接收8架窄体客机，其中5架归属香港快运，3架归属国泰航空。</p>', 8, '36氪', 'https://36kr.com/p/3721135270247043?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-13 11:46:21.000000', '2026-03-16 06:50:55.160084', 'https://36kr.com/p/3721135270247043?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (71, '氪星晚报 ｜魅族手机“解体”：做车机，做AI，或者离开；美团王莆中：建设物理世界AI底座，帮每个商家都用上自己的AI助理', '大公司：
  小鹏汽车机器人的步态调整专利公布
  36氪获悉，爱企查App显示，近日，广州小鹏汽车科技有限公司一项名为“机器人的步态调整方法、装置、设备及存储介质”的发明专利公布。专利摘要显示，本发明涉及智能机器人领域，公开了机器人的步态调整方法、装置、设备及存储介质，方法包括：获取仿人机器人脚部的目标采样点，以及每个目标采样点对应的坐标值和地形高程数据；依据每个目标采样点对应的坐标值和地形高程数据计算仿人机器人的落脚点回报值；获取每个目标采样点在预设半径内的地形高程数据最大值，依据坐标值和地形高程数据最大值计算仿人机器人的踢台阶回报值；依据落脚点回报值和踢台阶回报值对仿人机器人进行步态调整。本发明通过获取目标采样点坐标与地形高程数据，计算落脚点与踢台阶两类回报值，从而指导仿人机器人进行精准的步态调整，提升了机器人在楼梯等复杂地形中的自主运动适应性与稳定性。
  魅族手机“解体”：做车机，做AI，或者离开
  36氪从内部人士处独家获悉，魅族近期宣布一轮大调整，超50%的员工即将离开，涉及400人左右。这部分人有三个去处，其中，一部分将获得“N+2”的赔偿；魅族的“PANDAER”潮', '<h2>大公司：</h2>
  <p><strong>小鹏汽车机器人的步态调整专利公布</strong></p>
  <p>36氪获悉，爱企查App显示，近日，广州小鹏汽车科技有限公司一项名为“机器人的步态调整方法、装置、设备及存储介质”的发明专利公布。专利摘要显示，本发明涉及智能机器人领域，公开了机器人的步态调整方法、装置、设备及存储介质，方法包括：获取仿人机器人脚部的目标采样点，以及每个目标采样点对应的坐标值和地形高程数据；依据每个目标采样点对应的坐标值和地形高程数据计算仿人机器人的落脚点回报值；获取每个目标采样点在预设半径内的地形高程数据最大值，依据坐标值和地形高程数据最大值计算仿人机器人的踢台阶回报值；依据落脚点回报值和踢台阶回报值对仿人机器人进行步态调整。本发明通过获取目标采样点坐标与地形高程数据，计算落脚点与踢台阶两类回报值，从而指导仿人机器人进行精准的步态调整，提升了机器人在楼梯等复杂地形中的自主运动适应性与稳定性。</p>
  <p><strong>魅族手机“解体”：做车机，做AI，或者离开</strong></p>
  <p>36氪从内部人士处独家获悉，魅族近期宣布一轮大调整，超50%的员工即将离开，涉及400人左右。这部分人有三个去处，其中，一部分将获得“N+2”的赔偿；魅族的“PANDAER”潮牌团队将分拆，自负盈亏；魅族AR眼镜团队则部分被AR眼镜公司“雷鸟创新”吸收。经过调整后，魅族手机剩余员工只有400人左右，后续有两个去处，一部分整合进魅族的flyme车机团队，另一部分转向AI软件方向的探索。对于以上消息，魅族方面表示：未来，魅族将以Flyme开放生态系统为核心基座，构建可持续发展的良性业务闭环。基于战略转型的组织人员合理变动，属于行业发展过程中的正常现象，敬请各界放心。公司除暂停国内新手机硬件自研项目外，各项业务推进稳健，手机海外业务、AI眼镜智能硬件业务 及PANDAER潮流科技品牌业务都在正常运营。对于“雷鸟吸收”的信息，魅族方面称，消息不实。</p>
  <p><strong>滴滴四季度订单同比增长13.5%，日均订单量增至5265万单</strong></p>
  <p>3月13日，滴滴在其官网发布2025年第四季度及全年业绩报告。四季度，滴滴核心平台（中国出行和国际业务）订单量同比增长13.5%至48.44亿单，日均订单量增至5265万单。其中，中国出行同比增长10.1%至日均3890万单，国际业务同比增长24.5%至日均1375万单。同期，核心平台交易额（GTV）同比增长19.9%至1238亿元。中国出行和国际业务分别同比增长11.2%、47.1%至872亿元、366亿元。四季度滴滴实现经调整净利润5.3亿元。2025年全年，滴滴核心平台订单量同比增长14%，达到182.4亿单。核心平台全年交易额同比增长14.8%，至4508亿元。2025年全年滴滴经调EBITA实现盈利36.7亿元。</p>
  <p><strong>美团王莆中：建设物理世界AI底座，帮每个商家都用上自己的AI助理</strong></p>
  <p>3月13日，美团召开2026管理层沟通会。对于AI发展，美团核心本地商业CEO王莆中表示，美团将坚持加大投入，一层是投入研发物流、机器人等相关科技，譬如无人机、无人车等；另一层是建设丰富的物理世界信息、真实的评价，捕捉即时动态的信息，为模型、C端Agent所用。“帮商家去了解和改造物理世界，是我们非常清晰的战略。”王莆中表示，美团将帮每个商家都用上自己的AI助理。</p>
  <p><strong>复星集团旗下商盟科技增资至约2.1亿元</strong></p>
  <p>36氪获悉，爱企查App显示，近日，浙江商盟科技有限公司发生工商变更，新增复星集团旗下浙江复星商业发展有限公司为股东，注册资本由约1亿元人民币增至约2.1亿元人民币，增幅约104%，吴晓燕卸任法定代表人、董事长兼总经理，张珍接任法定代表人、董事长、经理。 浙江商盟科技有限公司成立于2009年8月，经营范围包括信息系统集成服务、信息系统运行维护服务、网络技术服务等。股东信息显示，该公司现由亚东星辰创业投资有限公司、宁波梅山保税港区统付企业管理合伙企业（有限合伙）及上述新增股东共同持股。</p>
  <p><strong>追觅预计下周发射第一颗太空算力卫星</strong></p>
  <p>自AWE中国家电及消费电子博览会的追觅展台现场获悉，追觅预计在下周发射第一颗太空算力卫星。此前该公司表示，计划未来发射200万颗太空算力卫星，打造算力组网系统。目前，这部分业务由追觅旗下芯际穿越负责。（界面）</p>
  <p><strong>Meta最新AI模型推迟发布，性能表现不如同行</strong></p>
  <p>有媒体曾报道称，Meta从去年12月研发一款代号为“牛油果（Avocado）”的文本人工智能模型，并计划在第一季度推出。然而最新消息称，Meta 已将“牛油果”人工智能模型代码的发布时间从3月至少推迟至5月。据知情人士透露，Meta耗时数月研发了这款AI模型，但其在内部推理、编码和写作测试中，性能表现却不及谷歌、OpenAI和Anthropic等竞争对手的领先人工智能模型。（财联社）</p>
  <p><strong>蔚来CEO李斌：神玑第二颗芯片成本便宜了1/3-1/2</strong></p>
  <p>36氪获悉，李斌近期在沟通会上透露，神玑第二颗芯片成本便宜了1/3-1/2。据了解，神玑第二颗芯片相当于三颗ORIN-X的算力，几个月前已经流片成功，有不少行业客户在进行前期测试与接触，目前在量产过程当中。</p>
  <p><strong>网易有道发布行业首个同传Agent</strong></p>
  <p>36氪获悉，网易有道率先推出行业首个“同传Agent”，继开源国内首个“龙虾”后再度加速Agent落地。目前用户可在有道词典/有道翻译首页进行体验。此次升级，有道同传Agent还新增录音转写功能，并在识别广度、准确率以及复杂场景适配性方面持续优化，为用户在真实场景中提供专业准确的结果。目前，该功能已支持 71种语言、125种口音的实时识别，不仅覆盖主流通用语言，还包括粤语、印度英语等常见特色口音，以适配更加多元的国际交流环境。</p>
  <h2>投融资：</h2>
  <p><strong>小鹏汇天再获近2亿美元股权融资</strong></p>
  <p>36氪获悉，小鹏汇天宣布于近期完成了近2亿美元的新一轮股权融资，投资机构包括高瓴创投、红杉中国、高榕创投、达晨财智等。其中，高瓴创投和红杉中国在A轮融资后继续追加投资。此轮融资后，汇天历史股权融资总额约10亿美元。</p>
  <h2>新产品：</h2>
  <p><strong>石头科技AWE展出三大品类全系新品</strong></p>
  <p>36氪获悉，石头科技在AWE 2026上集中展示扫地机器人、洗地机、洗衣机三大品类全系旗舰产品。其中，轮足扫地机器人G-Rover可跨越复式楼层障碍；G30S Pro越障高度达8.8cm。IDC报告数据显示，2025年石头科技在全球清洁机器人市场��份额为17.7%，在扫地机器人品类的市场份额达27.0%，销量与销额排名全球第一。</p>
  <p><strong>阿里云发布手机“一键养虾”产品JVS Claw</strong></p>
  <p>36氪获悉，3月13日，阿里云推出“一键养虾”平台——JVS Claw，消费者无需掌握任何代码知识，在手机上简单操作三步，就能拥有即开即用、智能进化、安全可控的AI智能体“龙虾”。全程无需配置节点和大模型API密钥，也不用绑定微信/飞书等IM工具。</p>
  <p><strong>货拉拉搬运工及保洁服务官宣上线</strong></p>
  <p>36氪获悉，货拉拉正式官宣上线“搬运工”及“保洁”两大新服务品类，其中“搬运工”除常规搬运外，还可提供遛狗、帮排队等各项服务。“保洁”则率先在深圳上线，覆盖家电清洗、日常保洁、深度保洁等场景。</p>
  <h2>今日观点：</h2>
  <p><strong>王兴：物理世界数字化将是AI非常重要的底座</strong></p>
  <p>36氪获悉，美团2026年管理层沟通会上，美团CEO王兴表示：“AI Agent对我的冲击比ChatGPT冲击更大，我们经历过从互联网到移动互联网的变化，可以肯定的是，AI带来的变化会比整个互联网带来的变化要大得多，它注定会创造巨大生产力，也一定会对组织、对工作模式带来很大的变化。”王兴表示，对于美团来说，物理世界的数字化将是AI非常重要的底座，“虽然大模型越来越聪明。但我们可以想象，就算爱因斯坦当秘书，让他订一个餐厅，他依然不知道那个餐厅有没有座位。这不是智力问题，而是信息问题。”</p>
  <h2>其他值得关注的新闻：</h2>
  <p><strong>中办、国办：优化革命老区城镇布局，支持具备条件的城市打造省域副中心城市、省际交界地区区域性中心城市</strong></p>
  <p>36氪获悉，中共中央办公厅、国务院办公厅发布《关于加快革命老区振兴发展的意见》提出，提升新型城镇化水平。优化革命老区城镇布局，支持具备条件的城市打造省域副中心城市、省际交界地区区域性中心城市。推动县城人口集中、产业集聚，结合实际培育一批农业强县、工业大县、旅游名县等，加强规模较大的中心镇建设，促进农业转移人口就近城镇化。加力推进城镇老旧小区改造和城市排水防涝、污水收集处理等基础设施建设，', 8, '36氪', 'https://36kr.com/p/3721253543164549?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-13 11:07:56.000000', '2026-03-16 06:50:55.160111', 'https://36kr.com/p/3721253543164549?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (72, '魅族手机“解体”：做车机，做AI，或者离开丨智能涌现独家', '文｜邱晓芬
  编辑｜苏建勋 杨轩
  年前持续发酵的“魅族手机停摆”风波，今日落下帷幕。
  《智能涌现》从内部人士处独家获悉，魅族近期宣布一轮大调整，超50%的员工即将离开，涉及400人左右。
  这部分人有三个去处——其中，一部分将获得“N+2”的赔偿。
  消息人士称，“大多数人将在本周五之内办完（手续）”；
  魅族的“PANDAER”潮牌团队将分拆，自负盈亏；
  魅族AR眼镜团队则部分被AR眼镜公司「雷鸟创新」吸收。
  其实，早在2月27日，针对外界传言，魅族方面发布了名为《廿三载热爱，以Flyme之名新生》的公告，称“决定暂停手机新产品自研硬件项目，并正接洽第三方硬件合作伙伴”。
  而据《智能涌现》了解，经过调整后，魅族手机剩余员工只有400人左右，后续有两个去处，一部分整合进魅族的flyme车机团队，另一部分转向AI软件方向的探索。
  另外，魅族手机的补分核心资产目前已经被被打包、整合进吉利体系内的硬件公司，包括代码、手机产品文档、技术接口文档、代码文档、视觉动效文档等等。
  前述知情人士称，剩余的员工主要集中在珠海团队，接下来不再继续使用魅族的品牌，团队人员', '<p><strong>文｜邱晓芬</strong></p>
  <p><strong>编辑｜苏建勋 杨轩</strong></p>
  <p>年前持续发酵的“魅族手机停摆”风波，今日落下帷幕。</p>
  <p>《智能涌现》从内部人士处独家获悉，魅族近期宣布一轮大调整，<strong>超50%的员工即将离开，涉及400人左右。</strong></p>
  <p>这部分人有三个去处——其中，一部分将<strong>获得“N+2”的赔偿</strong>。</p>
  <p>消息人士称，“大多数人将在本周五之内办完（手续）”；</p>
  <p><strong>魅族的“PANDAER”潮牌团队将分拆</strong>，自负盈亏；</p>
  <p><strong>魅族AR眼镜团队则部分被AR眼镜公司「雷鸟创新」吸收。</strong></p>
  <p>其实，早在2月27日，针对外界传言，魅族方面发布了名为《廿三载热爱，以Flyme之名新生》的公告，称“决定暂停手机新产品自研硬件项目，并正接洽第三方硬件合作伙伴”。</p>
  <p>而据《智能涌现》了解，经过调整后，魅族手机剩余员工只有400人左右，<strong>后续有两个去处，一部分整合进魅族的flyme车机团队，另一部分转向AI软件方向的探索。</strong></p>
  <p><strong>另外，魅族手机的补分核心资产目前已经被被打包、整合进吉利体系内的硬件公司，包括代码、手机产品文档、技术接口文档、代码文档、视觉动效文档等等。</strong></p>
  <p>前述知情人士称，剩余的员工主要集中在珠海团队，接下来不再继续使用魅族的品牌，团队人员也或将更换公司主体。</p>
  <p>对于以上消息，魅族方面向《智能涌现》表示：未来，魅族将以Flyme开放生态系统为核心基座，构建可持续发展的良性业务闭环。基于战略转型的组织人员合理变动，属于行业发展过程中的正常现象，敬请各界放心。公司除暂停国内新手机硬件自研项目外，各项业务推进稳健，手机海外业务、AI眼镜智能硬件业务 及PANDAER潮流科技品牌业务都在正常运营。</p>
  <p>而对于“雷鸟吸收”的信息，魅族方面称，消息不实。&nbsp;</p>
  <p>“拥抱世界的变化，找到一条健康经营和持续的创新道路，成为春节前后公司上下的终极命题”，魅族方面在前述公告中表示。</p>
  <p>在春节前，魅族员工已经感受到了巨震的端倪——比如，在年前，魅族已经出现了解散外包员工、审批放缓、提早放假且推迟复工时间等现象。对此，多数员工将其解读为手机业务进展不顺的讯号。</p>
  <p>其实，据《智能涌现》了解，魅族手机此前一度有转圜空间。《智能涌现》获悉，在年前，魅族手机团队曾经寻求某家知名AI公司的收购，而后谈判失败，“因为对方认为魅族品牌没有价值”，消息人士称。</p>
  <p>谈及魅族，多位员工、粉丝难掩惋惜之情。“纪念陪伴我青春的伙伴”、“心情很遗憾”，许多魅族用户在超话中留言。</p>
  <p>魅族手机此前在公告中，直白指出了战略调整的本质原因正是内存涨价——“手机市场竞争激烈程度超乎想象......<strong>内存价格暴涨，让手机新产品的商业化变成不可为</strong>”。</p>
  <p>Counterpoint不久前发布的报告显示，2026年第一季度，DRAM的价格环比上涨50%、NAND价格环比上涨超90%。</p>
  <p>内存价格的上涨，已经悄然改变了手机的BOM成本结构：</p>
  <p>前述报告指出，低端手机（小于200美金）的内存成本占整机成本的43%，环比增长25%；</p>
  <p>中高端（＞400美金）价位段的手机，情况稍好一些，预计到今年第二季度，内存占整机成本比例预计分别上升至20%、23%。</p>
  <p>内存的暴涨，直接倾轧所有手机公司的生存空间。去年年底以来，中国的手机行业并不太平。</p>
  <p>今年1月份，手机厂商realme（真我）因内存涨价，宣布回归OPPO体系，以寻求协同作战，提高效率。</p>
  <p>3月份，大量手机厂商开启了近五年来最大规模的集体调价，OPPO、一加、vivo、小米、荣耀不同价位段机型都有500元不等的上浮，甚至有机型直接退出千元价位段。</p>
  <p>魅族手机的退出，是AI浪潮中成熟产业遭遇蝴蝶效应的一个缩影。</p>
  <p>只是，这场手机行业的地震还远没结束，这可能也是一个新旧时代交替的序章。</p>
  <p class="image-wrapper"><img src="https://img.36krcdn.com/hsossms/20260313/v2_7a198c03c55e4b8e8a6e38c0336615c2@1199336245_oswg44288oswg900oswg335_img_000?x-oss-process=image/format,jpg/interlace,1" /></p>
  <p class="img-desc">end</p>
  <p>&nbsp;</p>
  <p>&nbsp;</p>
  <p>&nbsp;</p>', 8, '36氪', 'https://36kr.com/p/3721227876039047?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-13 10:47:06.000000', '2026-03-16 06:50:55.160135', 'https://36kr.com/p/3721227876039047?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (73, '36氪 × OpenClaw"龙虾"｜让你的AI Agent先一步看到未来', '当AI Agent从“智能助手”进化为“行动者”，当OpenClaw“龙虾”成为无数开发者、创业者的高效协作伙伴，如何让你的AI智能体突破信息壁垒，精准链接行业核心资源？
