INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (74, '2026GDC在美国举办，AI相关议题分享超过100场', '36氪获悉，2026年游戏开发者大会（简称“GDC”）在美国旧金山举行。官方数据显示，为期5天的大会，有3万余名从业者到场参与，现场举办超700场议题分享与活动。其中，AI相关议题分享超过100场，较2025年增长超110%。本届大会吸引全球400多家科技及游戏厂商参与，腾讯、谷歌、苹果、英伟达、Meta、索尼、微软等亮相。今年，9家中国厂商共计带来27场AI相关议题分享，其中腾讯游戏达21场。', '36氪获悉，2026年游戏开发者大会（简称“GDC”）在美国旧金山举行。官方数据显示，为期5天的大会，有3万余名从业者到场参与，现场举办超700场议题分享与活动。其中，AI相关议题分享超过100场，较2025年增长超110%。本届大会吸引全球400多家科技及游戏厂商参与，腾讯、谷歌、苹果、英伟达、Meta、索尼、微软等亮相。今年，9家中国厂商共计带来27场AI相关议题分享，其中腾讯游戏达21场。', 8, '36氪', 'https://36kr.com/newsflashes/3723959543462281?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 08:47:32.000000', '2026-03-16 06:50:55.160167', 'https://36kr.com/newsflashes/3723959543462281?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (75, '食材以次充好 多地“刘文祥麻辣烫”门店被查', '“刘文祥鸭肉当猪肉牛肉卖”的相关话题冲上热搜。有媒体调查后发现，多家刘文祥门店存在食材以次充好、标注混乱等问题。据了解，福建厦门一家刘文祥门店的肥牛卷，在外卖平台标注为肥牛/牛肉，店员也宣称是牛肉，实则产品包装袋显示为鸭肉。福建漳州一家门店同样存在违规情况。3月14日晚，福建多地市场监管部门展开行动，突击检查刘文祥门店。目前，部分涉事门店已被要求立即整改。市场监管部门表示，将对以假冒真、虚假宣传的行为依法从严查处，并对辖区内所有连锁门店进行拉网式排查。（央视新闻）', '“刘文祥鸭肉当猪肉牛肉卖”的相关话题冲上热搜。有媒体调查后发现，多家刘文祥门店存在食材以次充好、标注混乱等问题。据了解，福建厦门一家刘文祥门店的肥牛卷，在外卖平台标注为肥牛/牛肉，店员也宣称是牛肉，实则产品包装袋显示为鸭肉。福建漳州一家门店同样存在违规情况。3月14日晚，福建多地市场监管部门展开行动，突击检查刘文祥门店。目前，部分涉事门店已被要求立即整改。市场监管部门表示，将对以假冒真、虚假宣传的行为依法从严查处，并对辖区内所有连锁门店进行拉网式排查。（央视新闻）', 8, '36氪', 'https://36kr.com/newsflashes/3723914585963138?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 08:21:42.000000', '2026-03-16 06:50:55.160179', 'https://36kr.com/newsflashes/3723914585963138?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (76, '艾迪药业：多替拉韦钠片获得药品注册批准', '艾迪药业3月15日公告，公司近日收到国家药品监督管理局核准签发的多替拉韦钠片《药品注册证书》。该药品为化学药品4类，规格为50mg（以 C20 H19 F2 N3 O5 计），批准的适应症为联合其它抗逆转录病毒药物，用于治疗人类免疫缺陷病毒（HIV）感染的成人和年满12岁的儿童患者。（界面）', '艾迪药业3月15日公告，公司近日收到国家药品监督管理局核准签发的多替拉韦钠片《药品注册证书》。该药品为化学药品4类，规格为50mg（以 C20 H19 F2 N3 O5 计），批准的适应症为联合其它抗逆转录病毒药物，用于治疗人类免疫缺陷病毒（HIV）感染的成人和年满12岁的儿童患者。（界面）', 8, '36氪', 'https://36kr.com/newsflashes/3723913729587584?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 08:13:50.000000', '2026-03-16 06:50:55.160189', 'https://36kr.com/newsflashes/3723913729587584?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (77, '兆驰股份：针对MicroLED在光通信等扩展领域的应用 目前处于样品验证测试阶段', '兆驰股份(002429.SZ)发布异动公告，公司注意到市场对MicroLED相关概念关注度较高。公司主营业务未发生改变，针对MicroLED在光通信等扩展领域的应用，目前处于样品验证测试阶段，短期内不会对公司经营业绩产生实质性影响。作为公司战略性新兴业务，激光芯片项目及高速光模块项目目前正处于稳步推进的投产初期阶段，产能爬坡及市场拓展需一定周期。公司光通信业务2025年上半年实现营业收入3.09亿元，占公司同期营业总收入84.83亿元的比例不足5%，业务规模占比较小。（财联社）', '兆驰股份(002429.SZ)发布异动公告，公司注意到市场对MicroLED相关概念关注度较高。公司主营业务未发生改变，针对MicroLED在光通信等扩展领域的应用，目前处于样品验证测试阶段，短期内不会对公司经营业绩产生实质性影响。作为公司战略性新兴业务，激光芯片项目及高速光模块项目目前正处于稳步推进的投产初期阶段，产能爬坡及市场拓展需一定周期。公司光通信业务2025年上半年实现营业收入3.09亿元，占公司同期营业总收入84.83亿元的比例不足5%，业务规模占比较小。（财联社）', 8, '36氪', 'https://36kr.com/newsflashes/3723912963914368?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 08:07:04.000000', '2026-03-16 06:50:55.160200', 'https://36kr.com/newsflashes/3723912963914368?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (78, '中长期资金去年底持有沪市ETF共1.5万亿元', '上海证券交易所创新产品部相关负责人近日在参加公开活动时表示，ETF已成为居民财富配置、中长期资金入市的重要载体。截至2025年底，中长期资金持有沪市ETF共1.5万亿元，年内增幅达70%，贡献了超四成的沪市ETF规模增量，其中保险持仓规模增长35%。（e公司）', '上海证券交易所创新产品部相关负责人近日在参加公开活动时表示，ETF已成为居民财富配置、中长期资金入市的重要载体。截至2025年底，中长期资金持有沪市ETF共1.5万亿元，年内增幅达70%，贡献了超四成的沪市ETF规模增量，其中保险持仓规模增长35%。（e公司）', 8, '36氪', 'https://36kr.com/newsflashes/3723873704556934?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 07:52:08.000000', '2026-03-16 06:50:55.160210', 'https://36kr.com/newsflashes/3723873704556934?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (79, '理想汽车汤靖：MEGA电池召回完成率已超过97.5%', '3月15日，理想汽车产品线负责人汤靖公布MEGA电池召回的最新进展。到现在召回完成率已经超过97.5%（总计11411台，已完成更换11128台），目前还有283位车主还没有完成更换。“虽然有云端安全提前的预警，但还是有潜在安全的隐患，还是建议尽快更换。”汤靖表示。
2025年10月31日，理想汽车宣布主动召回部分理想MEGA 2024款电动汽车，共计11411辆。本次召回范围内的车辆，由于该批次冷却液防腐性能不足，特定条件下会导致冷却回路中动力电池和前电机控制器的冷却铝板腐蚀渗漏，导致车辆出现故障灯点亮、动力受限及无法上电的情形，极端情况下会造成动力电池热失控，存在安全隐患。公司将为召回范围内车辆免费更换冷却液、动力电池和前电机控制器。（界面）', '3月15日，理想汽车产品线负责人汤靖公布MEGA电池召回的最新进展。到现在召回完成率已经超过97.5%（总计11411台，已完成更换11128台），目前还有283位车主还没有完成更换。“虽然有云端安全提前的预警，但还是有潜在安全的隐患，还是建议尽快更换。”汤靖表示。
2025年10月31日，理想汽车宣布主动召回部分理想MEGA 2024款电动汽车，共计11411辆。本次召回范围内的车辆，由于该批次冷却液防腐性能不足，特定条件下会导致冷却回路中动力电池和前电机控制器的冷却铝板腐蚀渗漏，导致车辆出现故障灯点亮、动力受限及无法上电的情形，极端情况下会造成动力电池热失控，存在安全隐患。公司将为召回范围内车辆免费更换冷却液、动力电池和前电机控制器。（界面）', 8, '36氪', 'https://36kr.com/newsflashes/3723873109227909?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 07:36:32.000000', '2026-03-16 06:50:55.160221', 'https://36kr.com/newsflashes/3723873109227909?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (80, '总投资5亿元，零重力新能源航空器第二总部项目签约落地无锡', '“无锡惠山发布”微信公众号消息，3月13日，总投资5亿元的零重力新能源航空器第二总部项目签约落地无锡惠山高新区。此次零重力投资惠山，将建设零重力全球首个6S旗舰店展销中心，倾转旋翼产品ZG-T6的研发及销售中心。（财联社）', '“无锡惠山发布”微信公众号消息，3月13日，总投资5亿元的零重力新能源航空器第二总部项目签约落地无锡惠山高新区。此次零重力投资惠山，将建设零重力全球首个6S旗舰店展销中心，倾转旋翼产品ZG-T6的研发及销售中心。（财联社）', 8, '36氪', 'https://36kr.com/newsflashes/3723867907242372?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 07:24:15.000000', '2026-03-16 06:50:55.160232', 'https://36kr.com/newsflashes/3723867907242372?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (81, 'Lucid即将推出Midsize平台，新车起售价低于5万美元', '3月15日，Lucid Group,Inc.宣布一项全面的财务与产品战略，旨在扩大业务规模，加速迈向盈利及实现正向自由现金流。
该公司概述了即将推出的Midsize平台的关键技术与战略要素，并发布了新一代Atlas电动驱动单元。该平台包含三款车型，前两款分别为Lucid Cosmos和Lucid Earth，起售价低于5万美元。
此外，公司正在与Uber敲定一项协议，以与Gravity自动驾驶出租车项目类似的规模部署Lucid Midsize平台车型，并计划随着时间推移逐步扩大规模。
该公司还推出了Lunar，这是一款基于Midsize平台的双座自动驾驶出租车概念车。（界面）', '3月15日，Lucid Group,Inc.宣布一项全面的财务与产品战略，旨在扩大业务规模，加速迈向盈利及实现正向自由现金流。
该公司概述了即将推出的Midsize平台的关键技术与战略要素，并发布了新一代Atlas电动驱动单元。该平台包含三款车型，前两款分别为Lucid Cosmos和Lucid Earth，起售价低于5万美元。
此外，公司正在与Uber敲定一项协议，以与Gravity自动驾驶出租车项目类似的规模部署Lucid Midsize平台车型，并计划随着时间推移逐步扩大规模。
该公司还推出了Lunar，这是一款基于Midsize平台的双座自动驾驶出租车概念车。（界面）', 8, '36氪', 'https://36kr.com/newsflashes/3723867099593094?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 07:13:30.000000', '2026-03-16 06:50:55.160242', 'https://36kr.com/newsflashes/3723867099593094?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (82, '从智能床到适老家具，660余项新国标激活品质消费', '据市场监管总局消息，2025年以来，市场监管总局（国家标准委）加快以高质量标准供给更好满足人民群众多样化的消费需求，发布消费品和服务相关国家标准660多项，扎实推进标准提质升级，持续发挥标准在保障消费安全、提升服务品质、优化消费环境、提振消费信心中的基础性、引领性作用。', '据市场监管总局消息，2025年以来，市场监管总局（国家标准委）加快以高质量标准供给更好满足人民群众多样化的消费需求，发布消费品和服务相关国家标准660多项，扎实推进标准提质升级，持续发挥标准在保障消费安全、提升服务品质、优化消费环境、提振消费信心中的基础性、引领性作用。', 8, '36氪', 'https://36kr.com/newsflashes/3723864380865159?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 07:10:44.000000', '2026-03-16 06:50:55.160252', 'https://36kr.com/newsflashes/3723864380865159?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (83, '阅文作家助手Claw开启内测', '36氪获悉，3月15日，阅文集团旗下专业网文创作工具“作家助手”宣布，作家助手Claw已开启内测。作家用户可一键完成安装部署，领养专属AI智能体，使用各种深度贴合网文创作场景的专属技能。', '36氪获悉，3月15日，阅文集团旗下专业网文创作工具“作家助手”宣布，作家助手Claw已开启内测。作家用户可一键完成安装部署，领养专属AI智能体，使用各种深度贴合网文创作场景的专属技能。', 8, '36氪', 'https://36kr.com/newsflashes/3723840436435584?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 06:46:22.000000', '2026-03-16 06:50:55.160261', 'https://36kr.com/newsflashes/3723840436435584?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (84, '中国互联网金融协会发布《关于OpenClaw在互联网金融行业应用安全的风险提示》', '36氪获悉，中国互联网金融协会提示称，OpenClaw智能体虽能提升工作效率，但其默认的高系统权限与弱安全配置，极易被攻击者利用，成为窃取敏感数据或非法操控交易的突破口，给行业带来严峻的风险挑战。中国互联网金融协会建议金融消费者在办理网上银行、证券交易、支付等个人金融业务的终端上极其谨慎安装OpenClaw。如确有必要安装，建议不授予金融服务类系统操作权限，及时跟进OpenClaw漏洞修复，严控功能插件安装，不在使用时输入身份证号、银行卡号、支付密码等敏感信息。另外，此类应用在运行过程中持续调用大模型接口，可能会产生较高的Token费用，建议使用者密切关注。', '36氪获悉，中国互联网金融协会提示称，OpenClaw智能体虽能提升工作效率，但其默认的高系统权限与弱安全配置，极易被攻击者利用，成为窃取敏感数据或非法操控交易的突破口，给行业带来严峻的风险挑战。中国互联网金融协会建议金融消费者在办理网上银行、证券交易、支付等个人金融业务的终端上极其谨慎安装OpenClaw。如确有必要安装，建议不授予金融服务类系统操作权限，及时跟进OpenClaw漏洞修复，严控功能插件安装，不在使用时输入身份证号、银行卡号、支付密码等敏感信息。另外，此类应用在运行过程中持续调用大模型接口，可能会产生较高的Token费用，建议使用者密切关注。', 8, '36氪', 'https://36kr.com/newsflashes/3723809260731012?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 06:14:40.000000', '2026-03-16 06:50:55.160271', 'https://36kr.com/newsflashes/3723809260731012?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (85, '钉钉或将发布多款AI硬件', '36氪获悉，钉钉预计将在3月17日发布会上，一次性推出多款新品，覆盖不止一个硬件品类。如果消息属实，这将是钉钉自去年推出AI录音卡片DingTalk A1以来，在硬件领域最大规模的一次动作。', '36氪获悉，钉钉预计将在3月17日发布会上，一次性推出多款新品，覆盖不止一个硬件品类。如果消息属实，这将是钉钉自去年推出AI录音卡片DingTalk A1以来，在硬件领域最大规模的一次动作。', 8, '36氪', 'https://36kr.com/newsflashes/3723794395871625?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 05:59:32.000000', '2026-03-16 06:50:55.160281', 'https://36kr.com/newsflashes/3723794395871625?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (86, '河南首家人形机器人4S店开业，租赁业务火热', '河南首家人形机器人4S店15日在郑州正式开业。当日，记者在这家机器人4S店看到，店内汇聚宇树、智元、乐聚等中国机器人龙头企业的多款主流产品，不仅展示、租赁、销售人形机器人产品，还提供数据采集、场景训练、模型迭代、售后运维等配套服务。
“顾客可以像选车一样对比多款主流机型，在实际场景中测试效能，获得定制化训练方案，大大降低使用门槛与风险。”负责运营该机器人4S店的河南具身智能产业发展有限公司业务经理陈杨受访时称，该店于今年1月底试营业以来，租赁业务火热。（证券时报）', '河南首家人形机器人4S店15日在郑州正式开业。当日，记者在这家机器人4S店看到，店内汇聚宇树、智元、乐聚等中国机器人龙头企业的多款主流产品，不仅展示、租赁、销售人形机器人产品，还提供数据采集、场景训练、模型迭代、售后运维等配套服务。
“顾客可以像选车一样对比多款主流机型，在实际场景中测试效能，获得定制化训练方案，大大降低使用门槛与风险。”负责运营该机器人4S店的河南具身智能产业发展有限公司业务经理陈杨受访时称，该店于今年1月底试营业以来，租赁业务火热。（证券时报）', 8, '36氪', 'https://36kr.com/newsflashes/3723779907893889?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 05:52:45.000000', '2026-03-16 06:50:55.160291', 'https://36kr.com/newsflashes/3723779907893889?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (87, '胖东来最新回应“鸡蛋人工色素超标”：采购手续齐全，已送检配合核查', '“正在配合市场管理部门对相关产品进行核查。”3月15日，针对鸡蛋被博主指人工色素超标一事，记者电采了胖东来，工作人员表示，“我们卖场售卖的生蛋产品，均通过正规的途径合法采购，手续都是齐全的，也得到了相应的进货查验的过程，暂时没有接到(下架)的通知。”3月13日，博主“王海测评”称，胖东来超市的鸡蛋检测出一种名为角黄素(斑蝥黄)的人工色素，含量为9.54mg/kg，超出农业农村部发布的《饲料添加剂安全使用规范》蛋禽类饲料中斑蝥黄允许的最大添加量8mg/kg。（新浪财经）', '“正在配合市场管理部门对相关产品进行核查。”3月15日，针对鸡蛋被博主指人工色素超标一事，记者电采了胖东来，工作人员表示，“我们卖场售卖的生蛋产品，均通过正规的途径合法采购，手续都是齐全的，也得到了相应的进货查验的过程，暂时没有接到(下架)的通知。”3月13日，博主“王海测评”称，胖东来超市的鸡蛋检测出一种名为角黄素(斑蝥黄)的人工色素，含量为9.54mg/kg，超出农业农村部发布的《饲料添加剂安全使用规范》蛋禽类饲料中斑蝥黄允许的最大添加量8mg/kg。（新浪财经）', 8, '36氪', 'https://36kr.com/newsflashes/3723778209937800?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 05:43:04.000000', '2026-03-16 06:50:55.160300', 'https://36kr.com/newsflashes/3723778209937800?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (88, '中国汽车流通协会40余家会员企业集体亮标准护消费', '3・15国际消费者权益日来临之际，中国汽车流通协会发起了“标准护航·透明消费”特别行动，40余家二手车、零配件会员企业面向全社会公开服务标准与质量承诺，切实守护消费者合法权益。本次行动中公开的企业标准，覆盖二手车流通、鉴定评估、零配件批发零售等各服务环节，通过标准化建设实现服务品质的统一、规范、透明，共同推动行业高质量发展。
其中，二手车企业：承诺无重大事故、无泡水车，提供完整车辆历史报告；鉴定评估机构：承诺检测过程全程录像，鉴定结果客观公正；零配件商家：承诺原厂/品牌件可溯源，品质透明有保障等等。
中国汽车流通协会提醒广大消费者，可以一键查询企业公开的执行标准，轻松获取服务质量保障依据：1.登录“企业标准信息公共服务平台”；2.输入关注的企业名称；3.点击搜索即可查看标准详情。（界面）', '3・15国际消费者权益日来临之际，中国汽车流通协会发起了“标准护航·透明消费”特别行动，40余家二手车、零配件会员企业面向全社会公开服务标准与质量承诺，切实守护消费者合法权益。本次行动中公开的企业标准，覆盖二手车流通、鉴定评估、零配件批发零售等各服务环节，通过标准化建设实现服务品质的统一、规范、透明，共同推动行业高质量发展。
其中，二手车企业：承诺无重大事故、无泡水车，提供完整车辆历史报告；鉴定评估机构：承诺检测过程全程录像，鉴定结果客观公正；零配件商家：承诺原厂/品牌件可溯源，品质透明有保障等等。
中国汽车流通协会提醒广大消费者，可以一键查询企业公开的执行标准，轻松获取服务质量保障依据：1.登录“企业标准信息公共服务平台”；2.输入关注的企业名称；3.点击搜索即可查看标准详情。（界面）', 8, '36氪', 'https://36kr.com/newsflashes/3723734440196489?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 04:58:33.000000', '2026-03-16 06:50:55.160310', 'https://36kr.com/newsflashes/3723734440196489?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (89, 'Meta被曝计划裁员20%甚至更多', '据路透社等媒体14日报道，美国科技巨头Meta正计划进行大规模裁员，裁员比例可能达到20%甚至更高。目的是节约成本，抵消巨额AI基础设施投入，并为AI辅助工作带来的效率提升做好准备。该公司宣布计划到2028年投入6000亿美元用于数据中心建设，同时斥资至少数十亿美元进行多项收购。为组建团队，Meta还向顶尖AI研究人员开出高达数亿美元的四年薪酬包。同时，公司对提升效率的要求也在一定程度上加速了裁员，公司首席执行官扎克伯格今年1月曾表示，他发现，过去需要大团队完成的项目，现在由一个非常有才华的人就能完成。这番言论似乎也为裁员埋下了伏笔。（e公司）', '据路透社等媒体14日报道，美国科技巨头Meta正计划进行大规模裁员，裁员比例可能达到20%甚至更高。目的是节约成本，抵消巨额AI基础设施投入，并为AI辅助工作带来的效率提升做好准备。该公司宣布计划到2028年投入6000亿美元用于数据中心建设，同时斥资至少数十亿美元进行多项收购。为组建团队，Meta还向顶尖AI研究人员开出高达数亿美元的四年薪酬包。同时，公司对提升效率的要求也在一定程度上加速了裁员，公司首席执行官扎克伯格今年1月曾表示，他发现，过去需要大团队完成的项目，现在由一个非常有才华的人就能完成。这番言论似乎也为裁员埋下了伏笔。（e公司）', 8, '36氪', 'https://36kr.com/newsflashes/3723723499174536?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 04:47:25.000000', '2026-03-16 06:50:55.160320', 'https://36kr.com/newsflashes/3723723499174536?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (90, '美宜佳总部回应多地门店卖假烟：已对全国4万家门店“拉网式”排查', '3月14日，据广东网络广播电视台立财经报道，大量网友反映在美宜佳便利店买到了“假烟”。美宜家总部客服告诉记者，总部已经在积极跟进此事，“目前的话已经在对全国4万家门店进行“拉网式”排查，如果发现有问题的门店会立即停业处理。”针对于被曝售卖假烟的门店，客服表示，“我们公司对这种售假行为零容忍严处罚，如果情况属实我们会从严追责，终止合作，后续也会进一步强化监管，严守合规经营底线。”（界面）', '3月14日，据广东网络广播电视台立财经报道，大量网友反映在美宜佳便利店买到了“假烟”。美宜家总部客服告诉记者，总部已经在积极跟进此事，“目前的话已经在对全国4万家门店进行“拉网式”排查，如果发现有问题的门店会立即停业处理。”针对于被曝售卖假烟的门店，客服表示，“我们公司对这种售假行为零容忍严处罚，如果情况属实我们会从严追责，终止合作，后续也会进一步强化监管，严守合规经营底线。”（界面）', 8, '36氪', 'https://36kr.com/newsflashes/3723703679990403?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 04:33:13.000000', '2026-03-16 06:50:55.160330', 'https://36kr.com/newsflashes/3723703679990403?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (91, '市场监管总局：2025年为消费者挽回经济损失43.5亿元', '据市场监管总局消息，2025年，全国市场监管部门通过全国12315平台、电话等渠道共受理消费者投诉、举报和咨询4386.6万件（投诉举报2646万件，同比增长9.8%），其中投诉2036.6万件，同比增长9.3%；举报609.4万件，同比增长11.4%；咨询1740.6万件，为消费者挽回经济损失43.5亿元，有力保护了消费者合法权益。（e公司）', '据市场监管总局消息，2025年，全国市场监管部门通过全国12315平台、电话等渠道共受理消费者投诉、举报和咨询4386.6万件（投诉举报2646万件，同比增长9.8%），其中投诉2036.6万件，同比增长9.3%；举报609.4万件，同比增长11.4%；咨询1740.6万件，为消费者挽回经济损失43.5亿元，有力保护了消费者合法权益。（e公司）', 8, '36氪', 'https://36kr.com/newsflashes/3723701443033734?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 04:24:59.000000', '2026-03-16 06:50:55.160340', 'https://36kr.com/newsflashes/3723701443033734?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (92, '黄金租赁变高利贷年利率超10倍', '近日，一些平台通过“租赁”或分期购买手机、黄金等实物，变相开展“高利贷”。一名黄金租赁平台服务商向记者表示，只需投入3-5万元加盟费，便可获得超1000%的年收益，其目标客户直指有稳定流水的个体商户、外卖员等，甚至"以贷养贷"人群。该服务商透露，平台可对接公证处，在支付公证部门抽成20%后，能为手机、黄金、汽车等相关合同办理“赋强公证”。所谓“赋强公证”，是指赋予强制执行效力的法律文书，赋强公证一旦做出，即具有法律效力。服务商表示，有了公证书后，违约不需要去法院起诉，可直接出强制执行书。（新浪财经）', '近日，一些平台通过“租赁”或分期购买手机、黄金等实物，变相开展“高利贷”。一名黄金租赁平台服务商向记者表示，只需投入3-5万元加盟费，便可获得超1000%的年收益，其目标客户直指有稳定流水的个体商户、外卖员等，甚至"以贷养贷"人群。该服务商透露，平台可对接公证处，在支付公证部门抽成20%后，能为手机、黄金、汽车等相关合同办理“赋强公证”。所谓“赋强公证”，是指赋予强制执行效力的法律文书，赋强公证一旦做出，即具有法律效力。服务商表示，有了公证书后，违约不需要去法院起诉，可直接出强制执行书。（新浪财经）', 8, '36氪', 'https://36kr.com/newsflashes/3723665291573635?f=rss', '', 'industry', '["\u79d1\u6280", "\u6295\u8d44", "\u521b\u4e1a"]', '2026-03-15 04:01:08.000000', '2026-03-16 06:50:55.160350', 'https://36kr.com/newsflashes/3723665291573635?f=rss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (93, '于东来最新回应胖东来“40亿资产分配”', '3月14日，胖东来创始人于东来在社交平台发文，对胖东来“40亿元资产分配”一事进行说明。
声明称，“40亿资产分配”其实沿用了胖东来已经持续二十多年的分配体制，因为近期要建梦之城门店，所以把资产转化为股本，“避免未来出现财务分配问题，目的是让企业明明白白地安全经营和发展”。
于东来还提到，自己在分配中占比5%左右（约2亿元人民币）。
此外，于东来表示，网络上经常有个别人故意扭曲事实、含沙射影地制造社会矛盾，制造零元购等歪曲事实的造谣现象，“严重的我们会走法律途径，避免给社会造成更严重的负面影响。”（界面）', '3月14日，胖东来创始人于东来在社交平台发文，对胖东来“40亿元资产分配”一事进行说明。
