INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (326, 'Continuously hardening ChatGPT Atlas against prompt injection', 'OpenAI is strengthening ChatGPT Atlas against prompt injection attacks using automated red teaming trained with reinforcement learning. This proactive discover-and-patch loop helps identify novel exploits early and harden the browser agent’s defenses as AI becomes more agentic.', 'OpenAI is strengthening ChatGPT Atlas against prompt injection attacks using automated red teaming trained with reinforcement learning. This proactive discover-and-patch loop helps identify novel exploits early and harden the browser agent’s defenses as AI becomes more agentic.', 14, 'OpenAI Blog', 'https://openai.com/index/hardening-atlas-against-prompt-injection', '', 'ai_tech', '["GPT", "Security", "AI", "OpenAI"]', '2025-12-22 00:00:00.000000', '2026-03-16 06:51:03.534880', 'https://openai.com/index/hardening-atlas-against-prompt-injection', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (327, 'Evaluating chain-of-thought monitorability', 'OpenAI introduces a new framework and evaluation suite for chain-of-thought monitorability, covering 13 evaluations across 24 environments. Our findings show that monitoring a model’s internal reasoning is far more effective than monitoring outputs alone, offering a promising path toward scalable control as AI systems grow more capable.', 'OpenAI introduces a new framework and evaluation suite for chain-of-thought monitorability, covering 13 evaluations across 24 environments. Our findings show that monitoring a model’s internal reasoning is far more effective than monitoring outputs alone, offering a promising path toward scalable control as AI systems grow more capable.', 14, 'OpenAI Blog', 'https://openai.com/index/evaluating-chain-of-thought-monitorability', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2025-12-18 12:00:00.000000', '2026-03-16 06:51:03.534890', 'https://openai.com/index/evaluating-chain-of-thought-monitorability', 0.0, 0);
