INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (508, 'GPT-5 System Card', 'This GPT-5 system card explains how a unified model routing system powers fast and smart responses using gpt-5-main, gpt-5-thinking, and lightweight versions like gpt-5-thinking-nano, optimized for different tasks and developer use.', 'This GPT-5 system card explains how a unified model routing system powers fast and smart responses using gpt-5-main, gpt-5-thinking, and lightweight versions like gpt-5-thinking-nano, optimized for different tasks and developer use.', 14, 'OpenAI Blog', 'https://openai.com/index/gpt-5-system-card', '', 'ai_tech', '["AI", "GPT", "Publication", "OpenAI"]', '2025-08-07 00:00:00.000000', '2026-03-16 06:51:03.536682', 'https://openai.com/index/gpt-5-system-card', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (509, 'Providing ChatGPT to the Entire U.S. Federal Workforce', 'Today, OpenAI for Government is announcing a new partnership with the U.S. General Services Administration (GSA) to launch a transformative initiative. For the next year, ChatGPT Enterprise will be available to the entire federal executive branch workforce at essentially no cost.', 'Today, OpenAI for Government is announcing a new partnership with the U.S. General Services Administration (GSA) to launch a transformative initiative. For the next year, ChatGPT Enterprise will be available to the entire federal executive branch workforce at essentially no cost.', 14, 'OpenAI Blog', 'https://openai.com/index/providing-chatgpt-to-the-entire-us-federal-workforce', '', 'ai_tech', '["GPT", "AI", "OpenAI"]', '2025-08-06 00:00:00.000000', '2026-03-16 06:51:03.536743', 'https://openai.com/index/providing-chatgpt-to-the-entire-us-federal-workforce', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (510, 'gpt-oss-120b & gpt-oss-20b Model Card', 'We introduce gpt-oss-120b and gpt-oss-20b, two open-weight reasoning models available under the Apache 2.0 license and our gpt-oss usage policy.', 'We introduce gpt-oss-120b and gpt-oss-20b, two open-weight reasoning models available under the Apache 2.0 license and our gpt-oss usage policy.', 14, 'OpenAI Blog', 'https://openai.com/index/gpt-oss-model-card', '', 'ai_tech', '["GPT", "AI", "OpenAI"]', '2025-08-05 00:00:00.000000', '2026-03-16 06:51:03.536752', 'https://openai.com/index/gpt-oss-model-card', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (511, 'Open Weights and AI for All', 'AI’s next frontier isn’t just about capability—it’s about who gets to use it. Our mission to put AI in the hands of as many people as possible is what drives us. Today’s release of our most capable  open-weights models is a major step forward that makes advanced AI more open, flexible, and accessible worldwide.', 'AI’s next frontier isn’t just about capability—it’s about who gets to use it. Our mission to put AI in the hands of as many people as possible is what drives us. Today’s release of our most capable  open-weights models is a major step forward that makes advanced AI more open, flexible, and accessible worldwide.', 14, 'OpenAI Blog', 'https://openai.com/global-affairs/open-weights-and-ai-for-all', '', 'ai_tech', '["GPT", "AI", "OpenAI"]', '2025-08-05 00:00:00.000000', '2026-03-16 06:51:03.536771', 'https://openai.com/global-affairs/open-weights-and-ai-for-all', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (512, 'Introducing gpt-oss', 'We’re releasing gpt-oss-120b and gpt-oss-20b—two state-of-the-art open-weight language models that deliver strong real-world performance at low cost. Available under the flexible Apache 2.0 license, these models outperform similarly sized open models on reasoning tasks, demonstrate strong tool use capabilities, and are optimized for efficient deployment on consumer hardware.', 'We’re releasing gpt-oss-120b and gpt-oss-20b—two state-of-the-art open-weight language models that deliver strong real-world performance at low cost. Available under the flexible Apache 2.0 license, these models outperform similarly sized open models on reasoning tasks, demonstrate strong tool use capabilities, and are optimized for efficient deployment on consumer hardware.', 14, 'OpenAI Blog', 'https://openai.com/index/introducing-gpt-oss', '', 'ai_tech', '["GPT", "AI", "OpenAI"]', '2025-08-05 00:00:00.000000', '2026-03-16 06:51:03.536761', 'https://openai.com/index/introducing-gpt-oss', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (513, 'Estimating worst case frontier risks of open weight LLMs', 'In this paper, we study the worst-case frontier risks of releasing gpt-oss. We introduce malicious fine-tuning (MFT), where we attempt to elicit maximum capabilities by fine-tuning gpt-oss to be as capable as possible in two domains: biology and cybersecurity.', 'In this paper, we study the worst-case frontier risks of releasing gpt-oss. We introduce malicious fine-tuning (MFT), where we attempt to elicit maximum capabilities by fine-tuning gpt-oss to be as capable as possible in two domains: biology and cybersecurity.', 14, 'OpenAI Blog', 'https://openai.com/index/estimating-worst-case-frontier-risks-of-open-weight-llms', '', 'ai_tech', '["GPT", "AI", "OpenAI"]', '2025-08-05 00:00:00.000000', '2026-03-16 06:51:03.536780', 'https://openai.com/index/estimating-worst-case-frontier-risks-of-open-weight-llms', 0.0, 0);
