INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (539, 'AI in Australia—OpenAI’s Economic Blueprint', 'Today, OpenAI, in partnership with Mandala Partners, is sharing the OpenAI AI Economic Blueprint for Australia. At a time when boosting productivity has emerged as a national priority for Australia, the Blueprint provides a clear, actionable plan for how Australia can unlock the full economic and social potential of artificial intelligence.', 'Today, OpenAI, in partnership with Mandala Partners, is sharing the OpenAI AI Economic Blueprint for Australia. At a time when boosting productivity has emerged as a national priority for Australia, the Blueprint provides a clear, actionable plan for how Australia can unlock the full economic and social potential of artificial intelligence.', 14, 'OpenAI Blog', 'https://openai.com/global-affairs/openais-australia-economic-blueprint', '', 'ai_tech', '["Company", "GPT", "AI", "OpenAI"]', '2025-06-30 07:00:00.000000', '2026-03-16 06:51:03.537034', 'https://openai.com/global-affairs/openais-australia-economic-blueprint', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (540, 'Customizable, no-code voice agent automation with GPT-4o', 'Retell AI is transforming the call center with AI voice automation powered by GPT-4o and GPT-4.1. Its no-code platform enables businesses to launch natural, real-time voice agents that cut call costs, boost CSAT, and automate customer conversations—without scripts or hold times.', 'Retell AI is transforming the call center with AI voice automation powered by GPT-4o and GPT-4.1. Its no-code platform enables businesses to launch natural, real-time voice agents that cut call costs, boost CSAT, and automate customer conversations—without scripts or hold times.', 14, 'OpenAI Blog', 'https://openai.com/index/retell-ai', '', 'ai_tech', '["API", "GPT", "AI", "OpenAI"]', '2025-06-26 10:00:00.000000', '2026-03-16 06:51:03.537044', 'https://openai.com/index/retell-ai', 0.0, 0);
