INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (547, 'How we’re responding to The New York Times’ data demands in order to protect user privacy', 'OpenAI is fighting a court order at the demands of The New York Times and plaintiffs, which involves retention of consumer ChatGPT and API user data indefinitely. Learn how we’re working to uphold user privacy, address legal requirements, and stay true to our data protection commitments.', 'OpenAI is fighting a court order at the demands of The New York Times and plaintiffs, which involves retention of consumer ChatGPT and API user data indefinitely. Learn how we’re working to uphold user privacy, address legal requirements, and stay true to our data protection commitments.', 14, 'OpenAI Blog', 'https://openai.com/index/response-to-nyt-data-demands', '', 'ai_tech', '["GPT", "Security", "AI", "OpenAI"]', '2025-06-05 16:30:00.000000', '2026-03-16 06:51:03.537112', 'https://openai.com/index/response-to-nyt-data-demands', 0.0, 0);
