INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (555, 'Introducing Codex', 'Introducing Codex: a cloud-based software engineering agent that can work on many tasks in parallel, powered by codex-1. With Codex, developers can simultaneously deploy multiple agents to independently handle coding tasks such as writing features, answering questions about your codebase, fixing bugs, and proposing pull requests for review.', 'Introducing Codex: a cloud-based software engineering agent that can work on many tasks in parallel, powered by codex-1. With Codex, developers can simultaneously deploy multiple agents to independently handle coding tasks such as writing features, answering questions about your codebase, fixing bugs, and proposing pull requests for review.', 14, 'OpenAI Blog', 'https://openai.com/index/introducing-codex', '', 'ai_tech', '["AI", "GPT", "Release", "OpenAI"]', '2025-05-16 08:00:00.000000', '2026-03-16 06:51:03.537191', 'https://openai.com/index/introducing-codex', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (556, 'Addendum to o3 and o4-mini system card: Codex', 'Codex is a cloud-based coding agent. Codex is powered by codex-1, a version of OpenAI o3 optimized for software engineering. codex-1 was trained using reinforcement learning on real-world coding tasks in a variety of environments to generate code that closely mirrors human style and PR preferences, adheres precisely to instructions, and iteratively runs tests until passing results are achieved.', 'Codex is a cloud-based coding agent. Codex is powered by codex-1, a version of OpenAI o3 optimized for software engineering. codex-1 was trained using reinforcement learning on real-world coding tasks in a variety of environments to generate code that closely mirrors human style and PR preferences, adheres precisely to instructions, and iteratively runs tests until passing results are achieved.', 14, 'OpenAI Blog', 'https://openai.com/index/o3-o4-mini-codex-system-card-addendum', '', 'ai_tech', '["GPT", "AI", "OpenAI"]', '2025-05-16 08:00:00.000000', '2026-03-16 06:51:03.537200', 'https://openai.com/index/o3-o4-mini-codex-system-card-addendum', 0.0, 0);
