INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (807, 'Video generation models as world simulators', 'We explore large-scale training of generative models on video data. Specifically, we train text-conditional diffusion models jointly on videos and images of variable durations, resolutions and aspect ratios. We leverage a transformer architecture that operates on spacetime patches of video and image latent codes. Our largest model, Sora, is capable of generating a minute of high fidelity video. Our results suggest that scaling video generation models is a promising path towards building general ', 'We explore large-scale training of generative models on video data. Specifically, we train text-conditional diffusion models jointly on videos and images of variable durations, resolutions and aspect ratios. We leverage a transformer architecture that operates on spacetime patches of video and image latent codes. Our largest model, Sora, is capable of generating a minute of high fidelity video. Our results suggest that scaling video generation models is a promising path towards building general purpose simulators of the physical world.', 14, 'OpenAI Blog', 'https://openai.com/index/video-generation-models-as-world-simulators', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2024-02-15 08:00:00.000000', '2026-03-16 06:51:03.539960', 'https://openai.com/index/video-generation-models-as-world-simulators', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (808, 'Disrupting malicious uses of AI by state-affiliated threat actors', 'We terminated accounts associated with state-affiliated threat actors. Our findings show our models offer only limited, incremental capabilities for malicious cybersecurity tasks.', 'We terminated accounts associated with state-affiliated threat actors. Our findings show our models offer only limited, incremental capabilities for malicious cybersecurity tasks.', 14, 'OpenAI Blog', 'https://openai.com/index/disrupting-malicious-uses-of-ai-by-state-affiliated-threat-actors', '', 'ai_tech', '["AI", "GPT", "Safety", "OpenAI"]', '2024-02-14 08:00:00.000000', '2026-03-16 06:51:03.539969', 'https://openai.com/index/disrupting-malicious-uses-of-ai-by-state-affiliated-threat-actors', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (809, 'Memory and new controls for ChatGPT', 'We’re testing the ability for ChatGPT to remember things you discuss to make future chats more helpful. You’re in control of ChatGPT’s memory.', 'We’re testing the ability for ChatGPT to remember things you discuss to make future chats more helpful. You’re in control of ChatGPT’s memory.', 14, 'OpenAI Blog', 'https://openai.com/index/memory-and-new-controls-for-chatgpt', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Product"]', '2024-02-13 00:00:00.000000', '2026-03-16 06:51:03.539978', 'https://openai.com/index/memory-and-new-controls-for-chatgpt', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (810, 'Response to NIST Executive Order on AI', 'The National Institute of Standards and Technology (NIST) request for information related to its assignments under sections 4.1, 4.5, and 11 of the Executive Order Concerning Artificial Intelligence', 'The National Institute of Standards and Technology (NIST) request for information related to its assignments under sections 4.1, 4.5, and 11 of the Executive Order Concerning Artificial Intelligence', 14, 'OpenAI Blog', 'https://openai.com/global-affairs/response-to-nist-executive-order-on-ai', '', 'ai_tech', '["AI", "GPT", "Global Affairs", "OpenAI"]', '2024-02-02 00:00:00.000000', '2026-03-16 06:51:03.539987', 'https://openai.com/global-affairs/response-to-nist-executive-order-on-ai', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (811, 'Building an early warning system for LLM-aided biological threat creation', 'We’re developing a blueprint for evaluating the risk that a large language model (LLM) could aid someone in creating a biological threat. In an evaluation involving both biology experts and students, we found that GPT-4 provides at most a mild uplift in biological threat creation accuracy. While this uplift is not large enough to be conclusive, our finding is a starting point for continued research and community deliberation.', 'We’re developing a blueprint for evaluating the risk that a large language model (LLM) could aid someone in creating a biological threat. In an evaluation involving both biology experts and students, we found that GPT-4 provides at most a mild uplift in biological threat creation accuracy. While this uplift is not large enough to be conclusive, our finding is a starting point for continued research and community deliberation.', 14, 'OpenAI Blog', 'https://openai.com/index/building-an-early-warning-system-for-llm-aided-biological-threat-creation', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2024-01-31 08:00:00.000000', '2026-03-16 06:51:03.539996', 'https://openai.com/index/building-an-early-warning-system-for-llm-aided-biological-threat-creation', 0.0, 0);
