INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (864, 'Improving mathematical reasoning with process supervision', 'We''ve trained a model to achieve a new state-of-the-art in mathematical problem solving by rewarding each correct step of reasoning (“process supervision”) instead of simply rewarding the correct final answer (“outcome supervision”). In addition to boosting performance relative to outcome supervision, process supervision also has an important alignment benefit: it directly trains the model to produce a chain-of-thought that is endorsed by humans.', 'We''ve trained a model to achieve a new state-of-the-art in mathematical problem solving by rewarding each correct step of reasoning (“process supervision”) instead of simply rewarding the correct final answer (“outcome supervision”). In addition to boosting performance relative to outcome supervision, process supervision also has an important alignment benefit: it directly trains the model to produce a chain-of-thought that is endorsed by humans.', 14, 'OpenAI Blog', 'https://openai.com/index/improving-mathematical-reasoning-with-process-supervision', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2023-05-31 07:00:00.000000', '2026-03-16 06:51:03.540486', 'https://openai.com/index/improving-mathematical-reasoning-with-process-supervision', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (865, 'Democratic inputs to AI', 'Our nonprofit organization, OpenAI, Inc., is launching a program to award ten $100,000 grants to fund experiments in setting up a democratic process for deciding what rules AI systems should follow, within the bounds defined by the law.', 'Our nonprofit organization, OpenAI, Inc., is launching a program to award ten $100,000 grants to fund experiments in setting up a democratic process for deciding what rules AI systems should follow, within the bounds defined by the law.', 14, 'OpenAI Blog', 'https://openai.com/index/democratic-inputs-to-ai', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2023-05-25 07:00:00.000000', '2026-03-16 06:51:03.540495', 'https://openai.com/index/democratic-inputs-to-ai', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (866, 'Governance of superintelligence', 'Now is a good time to start thinking about the governance of superintelligence—future AI systems dramatically more capable than even AGI.', 'Now is a good time to start thinking about the governance of superintelligence—future AI systems dramatically more capable than even AGI.', 14, 'OpenAI Blog', 'https://openai.com/index/governance-of-superintelligence', '', 'ai_tech', '["GPT", "Safety & Alignment", "AI", "OpenAI"]', '2023-05-22 07:00:00.000000', '2026-03-16 06:51:03.540504', 'https://openai.com/index/governance-of-superintelligence', 0.0, 0);
