INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (885, 'OpenAI and Microsoft extend partnership', 'We’re happy to announce that OpenAI and Microsoft are extending our partnership.', 'We’re happy to announce that OpenAI and Microsoft are extending our partnership.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-and-microsoft-extend-partnership', '', 'ai_tech', '["Company", "GPT", "AI", "OpenAI"]', '2023-01-23 08:00:00.000000', '2026-03-16 06:51:03.540675', 'https://openai.com/index/openai-and-microsoft-extend-partnership', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (886, 'Forecasting potential misuses of language models for disinformation campaigns and how to reduce risk', 'OpenAI researchers collaborated with Georgetown University’s Center for Security and Emerging Technology and the Stanford Internet Observatory to investigate how large language models might be misused for disinformation purposes. The collaboration included an October 2021 workshop bringing together 30 disinformation researchers, machine learning experts, and policy analysts, and culminated in a co-authored report building on more than a year of research. This report outlines the threats that lan', 'OpenAI researchers collaborated with Georgetown University’s Center for Security and Emerging Technology and the Stanford Internet Observatory to investigate how large language models might be misused for disinformation purposes. The collaboration included an October 2021 workshop bringing together 30 disinformation researchers, machine learning experts, and policy analysts, and culminated in a co-authored report building on more than a year of research. This report outlines the threats that language models pose to the information environment if used to augment disinformation campaigns and introduces a framework for analyzing potential mitigations. Read the full report here.', 14, 'OpenAI Blog', 'https://openai.com/index/forecasting-misuse', '', 'ai_tech', '["GPT", "Safety & Alignment", "AI", "OpenAI"]', '2023-01-11 08:00:00.000000', '2026-03-16 06:51:03.540686', 'https://openai.com/index/forecasting-misuse', 0.0, 0);
