INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (900, 'Our approach to alignment research', 'We are improving our AI systems’ ability to learn from human feedback and to assist humans at evaluating AI. Our goal is to build a sufficiently aligned AI system that can help us solve all other alignment problems.', 'We are improving our AI systems’ ability to learn from human feedback and to assist humans at evaluating AI. Our goal is to build a sufficiently aligned AI system that can help us solve all other alignment problems.', 14, 'OpenAI Blog', 'https://openai.com/index/our-approach-to-alignment-research', '', 'ai_tech', '["GPT", "Safety & Alignment", "AI", "OpenAI"]', '2022-08-24 07:00:00.000000', '2026-03-16 06:51:03.540821', 'https://openai.com/index/our-approach-to-alignment-research', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (901, 'New and improved content moderation tooling', 'We are introducing a new and improved content moderation tool. The Moderation endpoint improves upon our previous content filter, and is available for free today to OpenAI API developers.', 'We are introducing a new and improved content moderation tool. The Moderation endpoint improves upon our previous content filter, and is available for free today to OpenAI API developers.', 14, 'OpenAI Blog', 'https://openai.com/index/new-and-improved-content-moderation-tooling', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Product"]', '2022-08-10 07:00:00.000000', '2026-03-16 06:51:03.540831', 'https://openai.com/index/new-and-improved-content-moderation-tooling', 0.0, 0);
