INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (918, 'Measuring Goodhart’s law', 'Goodhart’s law famously says: “When a measure becomes a target, it ceases to be a good measure.” Although originally from economics, it’s something we have to grapple with at OpenAI when figuring out how to optimize objectives that are difficult or costly to measure.', 'Goodhart’s law famously says: “When a measure becomes a target, it ceases to be a good measure.” Although originally from economics, it’s something we have to grapple with at OpenAI when figuring out how to optimize objectives that are difficult or costly to measure.', 14, 'OpenAI Blog', 'https://openai.com/index/measuring-goodharts-law', '', 'ai_tech', '["GPT", "Safety & Alignment", "AI", "OpenAI"]', '2022-04-13 07:00:00.000000', '2026-03-16 06:51:03.541054', 'https://openai.com/index/measuring-goodharts-law', 0.0, 0);
