INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1008, 'OpenAI Five Benchmark: Results', 'Yesterday, OpenAI Five won a best-of-three against a team of 99.95th percentile Dota players: Blitz, Cap, Fogged, Merlini, and MoonMeander—four of whom have played Dota professionally—in front of a live audience and 100,000 concurrent livestream viewers.', 'Yesterday, OpenAI Five won a best-of-three against a team of 99.95th percentile Dota players: Blitz, Cap, Fogged, Merlini, and MoonMeander—four of whom have played Dota professionally—in front of a live audience and 100,000 concurrent livestream viewers.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-five-benchmark-results', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2018-08-06 07:00:00.000000', '2026-03-16 06:51:03.541946', 'https://openai.com/index/openai-five-benchmark-results', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1009, 'Learning dexterity', 'We’ve trained a human-like robot hand to manipulate physical objects with unprecedented dexterity.', 'We’ve trained a human-like robot hand to manipulate physical objects with unprecedented dexterity.', 14, 'OpenAI Blog', 'https://openai.com/index/learning-dexterity', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2018-07-30 07:00:00.000000', '2026-03-16 06:51:03.541956', 'https://openai.com/index/learning-dexterity', 0.0, 0);
