INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1011, 'OpenAI Scholars 2018: Meet our Scholars', 'Our first class of OpenAI Scholars is underway, and you can now follow along as this group of experienced software developers becomes machine learning practitioners.', 'Our first class of OpenAI Scholars is underway, and you can now follow along as this group of experienced software developers becomes machine learning practitioners.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-scholars-2018-meet-our-scholars', '', 'ai_tech', '["Company", "GPT", "AI", "OpenAI"]', '2018-07-25 07:00:00.000000', '2026-03-16 06:51:03.541975', 'https://openai.com/index/openai-scholars-2018-meet-our-scholars', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1012, 'OpenAI Five Benchmark', 'The OpenAI Five Benchmark match is now over!', 'The OpenAI Five Benchmark match is now over!', 14, 'OpenAI Blog', 'https://openai.com/index/openai-five-benchmark', '', 'ai_tech', '["Company", "GPT", "AI", "OpenAI"]', '2018-07-18 07:00:00.000000', '2026-03-16 06:51:03.541984', 'https://openai.com/index/openai-five-benchmark', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1013, 'Glow: Better reversible generative models', 'We introduce Glow, a reversible generative model which uses invertible 1x1 convolutions. It extends previous work on reversible generative models and simplifies the architecture. Our model can generate realistic high resolution images, supports efficient sampling, and discovers features that can be used to manipulate attributes of data. We’re releasing code for the model and an online visualization tool so people can explore and build on these results.', 'We introduce Glow, a reversible generative model which uses invertible 1x1 convolutions. It extends previous work on reversible generative models and simplifies the architecture. Our model can generate realistic high resolution images, supports efficient sampling, and discovers features that can be used to manipulate attributes of data. We’re releasing code for the model and an online visualization tool so people can explore and build on these results.', 14, 'OpenAI Blog', 'https://openai.com/index/glow', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2018-07-09 07:00:00.000000', '2026-03-16 06:51:03.541994', 'https://openai.com/index/glow', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1014, 'Learning Montezuma’s Revenge from a single demonstration', 'We’ve trained an agent to achieve a high score of 74,500 on Montezuma’s Revenge from a single human demonstration, better than any previously published result. Our algorithm is simple: the agent plays a sequence of games starting from carefully chosen states from the demonstration, and learns from them by optimizing the game score using PPO, the same reinforcement learning algorithm that underpins OpenAI Five.', 'We’ve trained an agent to achieve a high score of 74,500 on Montezuma’s Revenge from a single human demonstration, better than any previously published result. Our algorithm is simple: the agent plays a sequence of games starting from carefully chosen states from the demonstration, and learns from them by optimizing the game score using PPO, the same reinforcement learning algorithm that underpins OpenAI Five.', 14, 'OpenAI Blog', 'https://openai.com/index/learning-montezumas-revenge-from-a-single-demonstration', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2018-07-04 07:00:00.000000', '2026-03-16 06:51:03.542004', 'https://openai.com/index/learning-montezumas-revenge-from-a-single-demonstration', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1015, 'OpenAI Five', 'Our team of five neural networks, OpenAI Five, has started to defeat amateur human teams at Dota 2.', 'Our team of five neural networks, OpenAI Five, has started to defeat amateur human teams at Dota 2.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-five', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2018-06-25 07:00:00.000000', '2026-03-16 06:51:03.542013', 'https://openai.com/index/openai-five', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1016, 'Retro Contest: Results', 'The first run of our Retro Contest—exploring the development of algorithms that can generalize from previous experience—is now complete.', 'The first run of our Retro Contest—exploring the development of algorithms that can generalize from previous experience—is now complete.', 14, 'OpenAI Blog', 'https://openai.com/index/retro-contest-results', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2018-06-22 07:00:00.000000', '2026-03-16 06:51:03.542022', 'https://openai.com/index/retro-contest-results', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1017, 'Learning policy representations in multiagent systems', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/learning-policy-representations-in-multiagent-systems', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2018-06-17 07:00:00.000000', '2026-03-16 06:51:03.542032', 'https://openai.com/index/learning-policy-representations-in-multiagent-systems', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1018, 'Improving language understanding with unsupervised learning', 'We’ve obtained state-of-the-art results on a suite of diverse language tasks with a scalable, task-agnostic system, which we’re also releasing. Our approach is a combination of two existing ideas: transformers and unsupervised pre-training. These results provide a convincing example that pairing supervised learning methods with unsupervised pre-training works very well; this is an idea that many have explored in the past, and we hope our result motivates further research into applying this idea ', 'We’ve obtained state-of-the-art results on a suite of diverse language tasks with a scalable, task-agnostic system, which we’re also releasing. Our approach is a combination of two existing ideas: transformers and unsupervised pre-training. These results provide a convincing example that pairing supervised learning methods with unsupervised pre-training works very well; this is an idea that many have explored in the past, and we hope our result motivates further research into applying this idea on larger and more diverse datasets.', 14, 'OpenAI Blog', 'https://openai.com/index/language-unsupervised', '', 'ai_tech', '["GPT", "Safety & Alignment", "AI", "OpenAI"]', '2018-06-11 07:00:00.000000', '2026-03-16 06:51:03.542042', 'https://openai.com/index/language-unsupervised', 0.0, 0);
