INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1030, 'On first-order meta-learning algorithms', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/on-first-order-meta-learning-algorithms', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2018-03-08 08:00:00.000000', '2026-03-16 06:51:03.542156', 'https://openai.com/index/on-first-order-meta-learning-algorithms', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1031, 'Reptile: A scalable meta-learning algorithm', 'We’ve developed a simple meta-learning algorithm called Reptile which works by repeatedly sampling a task, performing stochastic gradient descent on it, and updating the initial parameters towards the final parameters learned on that task. Reptile is the application of the Shortest Descent algorithm to the meta-learning setting, and is mathematically similar to first-order MAML (which is a version of the well-known MAML algorithm) that only needs black-box access to an optimizer such as SGD or A', 'We’ve developed a simple meta-learning algorithm called Reptile which works by repeatedly sampling a task, performing stochastic gradient descent on it, and updating the initial parameters towards the final parameters learned on that task. Reptile is the application of the Shortest Descent algorithm to the meta-learning setting, and is mathematically similar to first-order MAML (which is a version of the well-known MAML algorithm) that only needs black-box access to an optimizer such as SGD or Adam, with similar computational efficiency and performance.', 14, 'OpenAI Blog', 'https://openai.com/index/reptile', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2018-03-07 08:00:00.000000', '2026-03-16 06:51:03.542165', 'https://openai.com/index/reptile', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1032, 'OpenAI Scholars', 'We’re providing 6–10 stipends and mentorship to individuals from underrepresented groups to study deep learning full-time for 3 months and open-source a project.', 'We’re providing 6–10 stipends and mentorship to individuals from underrepresented groups to study deep learning full-time for 3 months and open-source a project.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-scholars', '', 'ai_tech', '["Company", "GPT", "AI", "OpenAI"]', '2018-03-06 08:00:00.000000', '2026-03-16 06:51:03.542175', 'https://openai.com/index/openai-scholars', 0.0, 0);
