INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1102, 'Special projects', 'Impactful scientific work requires working on the right problems—problems which are not just interesting, but whose solutions matter.', 'Impactful scientific work requires working on the right problems—problems which are not just interesting, but whose solutions matter.', 14, 'OpenAI Blog', 'https://openai.com/index/special-projects', '', 'ai_tech', '["Company", "GPT", "AI", "OpenAI"]', '2016-07-28 07:00:00.000000', '2026-03-16 06:51:03.542860', 'https://openai.com/index/special-projects', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1103, 'Concrete AI safety problems', 'We (along with researchers from Berkeley and Stanford) are co-authors on today’s paper led by Google Brain researchers, Concrete Problems in AI Safety. The paper explores many research problems around ensuring that modern machine learning systems operate as intended.', 'We (along with researchers from Berkeley and Stanford) are co-authors on today’s paper led by Google Brain researchers, Concrete Problems in AI Safety. The paper explores many research problems around ensuring that modern machine learning systems operate as intended.', 14, 'OpenAI Blog', 'https://openai.com/index/concrete-ai-safety-problems', '', 'ai_tech', '["GPT", "Safety & Alignment", "AI", "OpenAI"]', '2016-06-21 07:00:00.000000', '2026-03-16 06:51:03.542870', 'https://openai.com/index/concrete-ai-safety-problems', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1104, 'OpenAI technical goals', 'OpenAI’s mission is to build safe AI, and ensure AI’s benefits are as widely and evenly distributed as possible.', 'OpenAI’s mission is to build safe AI, and ensure AI’s benefits are as widely and evenly distributed as possible.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-technical-goals', '', 'ai_tech', '["Company", "GPT", "AI", "OpenAI"]', '2016-06-20 07:00:00.000000', '2026-03-16 06:51:03.542880', 'https://openai.com/index/openai-technical-goals', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1105, 'Generative models', 'This post describes four projects that share a common theme of enhancing or using generative models, a branch of unsupervised learning techniques in machine learning. In addition to describing our work, this post will tell you a bit more about generative models: what they are, why they are important, and where they might be going.', 'This post describes four projects that share a common theme of enhancing or using generative models, a branch of unsupervised learning techniques in machine learning. In addition to describing our work, this post will tell you a bit more about generative models: what they are, why they are important, and where they might be going.', 14, 'OpenAI Blog', 'https://openai.com/index/generative-models', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2016-06-16 07:00:00.000000', '2026-03-16 06:51:03.542889', 'https://openai.com/index/generative-models', 0.0, 0);
