INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1127, '“No technology has me dreaming bigger than AI”', 'a stylized design resembling the Ashoka Chakra with colorful network lines and text reading "भारत 2026 INDIA." A vertical line separates it from the Google logo on the right, all set against a light blue gradient background with a faint grid pattern.', '<img src="https://storage.googleapis.com/gweb-uniblog-publish-prod/images/AI-Google_2.max-600x600.format-webp.webp">Sundar Pichai gave remarks at the opening ceremony of the AI Impact Summit. Read a transcript of his speech.', 15, 'Google AI Blog', 'https://blog.google/company-news/inside-google/message-ceo/sundar-pichai-ai-impact-summit-2026/', 'Sundar Pichai', 'ai_tech', '["Google", "A message from our CEO", "\u6df1\u5ea6\u5b66\u4e60", "AI"]', '2026-02-19 04:30:00.000000', '2026-03-16 06:51:04.999656', 'https://blog.google/company-news/inside-google/message-ceo/sundar-pichai-ai-impact-summit-2026/', 0.0, 0);
